import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type GamePhase = 'betting' | 'locked' | 'spinning' | 'result';

export interface PlayerBet {
  username: string;
  number: string;
  amount: number;
}

export interface BetAction {
  id: string;
  amount: number;
}

export interface ChipProps {
  value: number;
  className?: string;
  size?: "xs" | "sm" | "md" | "lg" | "board" | "selector";
}

export interface GameRecord {
  id: number;
  result: number;
  betAmount: number;
  winAmount: number;
  timestamp: Date;
}

export const WHEEL_NUMBERS = [
  0, 32, 15, 19, 4, 21, 2, 25, 17, 34, 6, 27, 13, 36, 11, 30, 8, 23, 10, 5, 24, 16, 33, 1, 20, 14, 31, 9, 22, 18, 29, 7, 28, 12, 35, 3, 26
];

export const RED_NUMBERS = new Set([1, 3, 5, 7, 9, 12, 14, 16, 18, 19, 21, 23, 25, 27, 30, 32, 34, 36]);

export const CHIP_VALUES = [1, 2, 5, 10, 20];

export const BOT_NAMES = [
  'CryptoKing', 'LuckyLuke', 'WhaleWatcher', 'MoonShot', 'SatoshiFan', 
  'RoulettePro', 'HodlGang', 'IcpMaxi', 'DfinityDave', 'BetMaster',
  'SpinDoctor', 'RedBlack', 'ZeroHero', 'HighRoller'
];

import { RED_NUMBERS } from './constants';

export const getNumberColor = (num: number): string => {
  if (num === 0) return 'green';
  if (RED_NUMBERS.has(num)) return 'red';
  return 'black';
};

export const getChipColor = (value: number) => {
  if (value === 1) return 'bg-gray-300 text-gray-900 ring-gray-400'; 
  if (value === 2) return 'bg-blue-600 text-white ring-blue-400';
  if (value === 5) return 'bg-white text-gray-900 ring-yellow-500';
  if (value === 10) return 'bg-red-600 text-white ring-red-400';
  if (value === 20) return 'bg-emerald-600 text-white ring-emerald-400';
  return 'bg-gray-500';
};

export const getBetNumbers = (betId: string): number[] => {
  if (betId.includes('_')) {
      return betId.split('_').map(Number);
  }
  const n = parseInt(betId);
  if (!isNaN(n)) return [n];
  return [];
};

export const calculateWinnings = (result: number, bets: Record<string, number>): number => {
  let winnings = 0;
  Object.entries(bets).forEach(([betId, amount]) => {
      let isWin = false, multiplier = 0;

      if (betId.match(/^[\d_]+$/)) {
          const numbers = getBetNumbers(betId);
          if (numbers.includes(result)) { 
              isWin = true; 
              multiplier = 36 / numbers.length; 
          }
      } else {
          switch(betId) {
              case '1st12': isWin = result >= 1 && result <= 12; multiplier = 3; break;
              case '2nd12': isWin = result >= 13 && result <= 24; multiplier = 3; break;
              case '3rd12': isWin = result >= 25 && result <= 36; multiplier = 3; break;
              case '1-18': isWin = result >= 1 && result <= 18; multiplier = 2; break;
              case '19-36': isWin = result >= 19 && result <= 36; multiplier = 2; break;
              case 'EVEN': isWin = result !== 0 && result % 2 === 0; multiplier = 2; break;
              case 'ODD': isWin = result !== 0 && result % 2 !== 0; multiplier = 2; break;
              case 'RED': isWin = RED_NUMBERS.has(result); multiplier = 2; break;
              case 'BLACK': isWin = !RED_NUMBERS.has(result) && result !== 0; multiplier = 2; break;
              case 'row1': isWin = result !== 0 && result % 3 === 1; multiplier = 3; break;
              case 'row2': isWin = result !== 0 && result % 3 === 2; multiplier = 3; break;
              case 'row3': isWin = result !== 0 && result % 3 === 0; multiplier = 3; break;
          }
      }
      if (isWin) winnings += amount * multiplier;
  });
  return winnings;
};

export const getHotCold = (history: number[]) => {
  const freq: Record<number, number> = {};
  for (let i = 0; i <= 36; i++) freq[i] = 0;
  history.slice(0, 50).forEach(n => freq[n]++);
  const sorted = Object.entries(freq).sort((a, b) => b[1] - a[1]);
  return { 
      hot: sorted.slice(0, 3).map(([n]) => +n), 
      cold: sorted.slice(-3).reverse().map(([n]) => +n) 
  };
};

class SoundManager {
    private ctx: AudioContext | null = null;
    private gain: GainNode | null = null;
    private muted = false;

    private init() {
        if (!this.ctx) {
            this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
            this.gain = this.ctx.createGain();
            this.gain.connect(this.ctx.destination);
        }
        if (this.ctx.state === 'suspended') this.ctx.resume();
    }

    setMuted(m: boolean) {
        this.muted = m;
        if (this.gain) this.gain.gain.value = m ? 0 : 1;
    }

    playChipSelect() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const o = this.ctx.createOscillator();
        const g = this.ctx.createGain();
        o.connect(g);
        g.connect(this.gain);
        o.frequency.setValueAtTime(1800, this.ctx.currentTime);
        o.frequency.exponentialRampToValueAtTime(1200, this.ctx.currentTime + 0.03);
        g.gain.setValueAtTime(0.2, this.ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.06);
        o.start();
        o.stop(this.ctx.currentTime + 0.06);
    }

    playChipPlace() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const now = this.ctx.currentTime;

        // Ceramic click
        const o1 = this.ctx.createOscillator();
        const g1 = this.ctx.createGain();
        const f1 = this.ctx.createBiquadFilter();
        o1.connect(f1);
        f1.connect(g1);
        g1.connect(this.gain);
        o1.type = 'triangle';
        o1.frequency.setValueAtTime(2800, now);
        o1.frequency.exponentialRampToValueAtTime(1200, now + 0.04);
        f1.type = 'bandpass';
        f1.frequency.value = 2000;
        f1.Q.value = 2;
        g1.gain.setValueAtTime(0.3, now);
        g1.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
        o1.start();
        o1.stop(now + 0.1);

        // Thump
        const o2 = this.ctx.createOscillator();
        const g2 = this.ctx.createGain();
        o2.connect(g2);
        g2.connect(this.gain);
        o2.frequency.setValueAtTime(150, now);
        o2.frequency.exponentialRampToValueAtTime(60, now + 0.08);
        g2.gain.setValueAtTime(0.25, now);
        g2.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
        o2.start();
        o2.stop(now + 0.1);
    }

    // Synchronized spin sound - takes duration parameter
    playSpinSound(duration = 4000) {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;

        const now = this.ctx.currentTime;
        const dur = duration / 1000;

        // Ball clicks - start fast, slow down (no scratching/friction)
        let t = 0;
        let interval = 0.04;
        for (let i = 0; i < 50 && t < dur - 0.5; i++) {
            const ct = now + t;
            const prog = t / dur;
            const o = this.ctx.createOscillator();
            const g = this.ctx.createGain();
            o.connect(g);
            g.connect(this.gain);
            o.frequency.setValueAtTime(1800 - prog * 800 + Math.random() * 200, ct);
            o.frequency.exponentialRampToValueAtTime(900, ct + 0.015);
            g.gain.setValueAtTime(0.15 * (1 - prog * 0.3), ct);
            g.gain.exponentialRampToValueAtTime(0.01, ct + 0.025);
            o.start(ct);
            o.stop(ct + 0.03);
            t += interval;
            interval *= 1.06; // Slow down
        }

        // Ball drop bounces - plays at end of spin
        const dropTime = now + dur - 0.4;
        const bounces = [
            { delay: 0, freq: 800, vol: 0.35 },
            { delay: 0.1, freq: 700, vol: 0.28 },
            { delay: 0.17, freq: 650, vol: 0.22 },
            { delay: 0.23, freq: 600, vol: 0.16 },
            { delay: 0.28, freq: 550, vol: 0.12 }
        ];

        bounces.forEach(({ delay, freq, vol }) => {
            const o = this.ctx!.createOscillator();
            const g = this.ctx!.createGain();
            o.connect(g);
            g.connect(this.gain!);
            o.frequency.setValueAtTime(freq, dropTime + delay);
            o.frequency.exponentialRampToValueAtTime(freq * 0.6, dropTime + delay + 0.06);
            g.gain.setValueAtTime(vol, dropTime + delay);
            g.gain.exponentialRampToValueAtTime(0.01, dropTime + delay + 0.08);
            o.start(dropTime + delay);
            o.stop(dropTime + delay + 0.08);
        });

        // Gentle suspense tone
        const so = this.ctx.createOscillator();
        const sg = this.ctx.createGain();
        so.connect(sg);
        sg.connect(this.gain);
        so.frequency.setValueAtTime(60, now);
        so.frequency.linearRampToValueAtTime(80, now + dur * 0.7);
        so.frequency.linearRampToValueAtTime(50, now + dur);
        sg.gain.setValueAtTime(0.03, now);
        sg.gain.linearRampToValueAtTime(0.08, now + dur * 0.8);
        sg.gain.linearRampToValueAtTime(0.01, now + dur);
        so.start(now);
        so.stop(now + dur);
    }

    playWin() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const now = this.ctx.currentTime;
        const notes = [523.25, 659.25, 783.99, 1046.50, 1318.51];
        notes.forEach((f, i) => {
            const o = this.ctx!.createOscillator();
            const g = this.ctx!.createGain();
            o.connect(g);
            g.connect(this.gain!);
            o.frequency.value = f;
            g.gain.setValueAtTime(0.25, now + i * 0.08);
            g.gain.exponentialRampToValueAtTime(0.01, now + i * 0.08 + 0.5);
            o.start(now + i * 0.08);
            o.stop(now + i * 0.08 + 0.5);
        });
    }

    playLose() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const o = this.ctx.createOscillator();
        const g = this.ctx.createGain();
        o.connect(g);
        g.connect(this.gain);
        o.frequency.setValueAtTime(350, this.ctx.currentTime);
        o.frequency.exponentialRampToValueAtTime(120, this.ctx.currentTime + 0.6);
        g.gain.setValueAtTime(0.15, this.ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.6);
        o.start();
        o.stop(this.ctx.currentTime + 0.6);
    }

    playUndo() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const o = this.ctx.createOscillator();
        const g = this.ctx.createGain();
        o.connect(g);
        g.connect(this.gain);
        o.frequency.setValueAtTime(800, this.ctx.currentTime);
        o.frequency.exponentialRampToValueAtTime(400, this.ctx.currentTime + 0.12);
        g.gain.setValueAtTime(0.2, this.ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.12);
        o.start();
        o.stop(this.ctx.currentTime + 0.12);
    }

    playClear() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const o = this.ctx.createOscillator();
        const g = this.ctx.createGain();
        o.connect(g);
        g.connect(this.gain);
        o.frequency.setValueAtTime(600, this.ctx.currentTime);
        o.frequency.exponentialRampToValueAtTime(300, this.ctx.currentTime + 0.15);
        g.gain.setValueAtTime(0.15, this.ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.15);
        o.start();
        o.stop(this.ctx.currentTime + 0.15);
    }
}

export const soundManager = new SoundManager();

import React, { useMemo } from 'react';
import { ArrowLeft, Volume2, VolumeX, Bell, ChevronUp, ChevronDown, X, RefreshCw, Undo2, Trash2, Play, History, Flame, Snowflake } from 'lucide-react';
import { getChipColor, getHotCold } from '../utils';
import { ChipProps, PlayerBet, GameRecord, CHIP_VALUES, RED_NUMBERS, GamePhase } from '../types';
import { soundManager } from '../services/SoundManager';

// ==========================================
// CASINO CHIP
// ==========================================
export const CasinoChip: React.FC<ChipProps> = ({ value, className = "", size = "md" }) => {
    const sizeClasses = {
        xs: "w-4 h-4 text-[6px] ring-1",
        sm: "w-5 h-5 text-[8px] ring-1",
        md: "w-8 h-8 text-[10px] ring-2",
        lg: "w-12 h-12 text-sm ring-[3px]",
        board: "w-4 h-4 text-[6px] ring-1 sm:w-5 sm:h-5 sm:text-[7px]",
        selector: "w-8 h-8 text-[9px] ring-2 sm:w-10 sm:h-10 sm:text-[10px] md:w-12 md:h-12 md:text-xs"
    };
    const currentSizeClass = sizeClasses[size] || sizeClasses.md;
    const colorClass = getChipColor(value);
    return (
        <div className={`${currentSizeClass} rounded-full flex items-center justify-center font-bold shadow-lg relative ${colorClass} ${className} transition-transform select-none ring-white/30`}>
            <div className="absolute inset-[15%] border border-dashed border-current opacity-40 rounded-full"></div>
            <span className="relative z-10">{value}</span>
        </div>
    );
};

// ==========================================
// NAV BAR
// ==========================================
export const NavBar: React.FC<{onExit: () => void; isMuted: boolean; setIsMuted: (v: boolean) => void}> = ({ onExit, isMuted, setIsMuted }) => {
    const handleMuteToggle = () => {
        const newMuted = !isMuted;
        setIsMuted(newMuted);
        soundManager.setMuted(newMuted);
    };
    return (
        <header className="flex items-center justify-between px-3 py-2.5 bg-[#1a1a2e] border-b border-white/5 shrink-0 shadow-sm z-50">
            <button onClick={onExit} className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-white/10 transition-colors">
                <ArrowLeft size={20} className="text-gray-400" />
            </button>
            <h1 className="text-base font-semibold text-white tracking-wide font-serif">ROYALE</h1>
            <div className="flex items-center gap-1">
                <button onClick={handleMuteToggle} className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-white/10 transition-colors">
                    {isMuted ? <VolumeX size={18} className="text-gray-400" /> : <Volume2 size={18} className="text-gray-400" />}
                </button>
                <button className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-white/10 transition-colors">
                    <Bell size={18} className="text-gray-400" />
                </button>
            </div>
        </header>
    );
};

// ==========================================
// LIVE FEED
// ==========================================
export const LiveFeed: React.FC<{feed: PlayerBet[]}> = ({ feed }) => (
    <div className="w-full bg-slate-900/80 overflow-hidden h-7 sm:h-8 flex items-center relative shrink-0 border-b border-white/5">
        <div className="absolute left-0 h-full w-8 bg-gradient-to-r from-slate-900 to-transparent z-10" />
        <div className="absolute right-0 h-full w-8 bg-gradient-to-l from-slate-900 to-transparent z-10" />
        <div className="whitespace-nowrap animate-marquee flex gap-6 px-4">
            {[...feed, ...feed].map((b, i) => (
                <div key={i} className="flex items-center gap-1.5 text-[10px] sm:text-xs text-gray-400">
                    <span className="font-bold text-white">{b.username}</span>
                    <span className="text-yellow-400">${b.amount}</span>
                    <span className={`px-1 rounded text-white text-[9px] font-bold ${
                        b.number === '0' ? 'bg-emerald-600' : RED_NUMBERS.has(+b.number) ? 'bg-red-600' : 'bg-black'
                    }`}>{b.number}</span>
                </div>
            ))}
        </div>
        <style>{`
            @keyframes marquee { 0% { transform: translateX(0); } 100% { transform: translateX(-50%); } }
            .animate-marquee { animation: marquee 30s linear infinite; }
        `}</style>
    </div>
);

// ==========================================
// BALANCE BAR
// ==========================================
export const BalanceBar: React.FC<{balance: number; betTotal: number; records: GameRecord[]; showRec: boolean; setShowRec: (v: boolean) => void}> = ({ 
    balance, betTotal, records, showRec, setShowRec
}) => {
    const latestRecord = records[0];
    const latestNet = latestRecord ? latestRecord.winAmount - latestRecord.betAmount : 0;
    let gainColor = 'text-gray-400';
    if (latestNet > 0) gainColor = 'text-emerald-400';
    else if (latestNet < 0) gainColor = 'text-red-400';

    return (
        <div className="relative shrink-0 z-40">
            <div className="flex items-center justify-end gap-3 px-3 py-1.5 bg-slate-900/60 border-b border-white/5">
                <span className="text-[10px] text-gray-500 uppercase tracking-wider">Balance</span>
                <span className="font-mono font-bold text-emerald-400 text-sm">${balance.toLocaleString()}</span>
                <div className="w-px h-4 bg-white/10" />
                <span className="text-[10px] text-gray-500 uppercase tracking-wider">Bet</span>
                <span className="font-mono font-bold text-yellow-400 text-sm">${betTotal.toLocaleString()}</span>
                <div className="w-px h-4 bg-white/10" />
                <button onClick={() => setShowRec(!showRec)} className="flex items-center gap-1.5 px-2 py-1 rounded hover:bg-white/5 transition-colors">
                    <span className="text-[10px] font-bold text-gray-500 uppercase tracking-wider">Last</span>
                    <span className={`font-mono font-bold text-sm ${gainColor}`}>
                        {latestNet > 0 ? '+' : ''}{latestNet === 0 ? '$0' : `$${latestNet}`}
                    </span>
                    {showRec ? <ChevronUp size={12} className="text-gray-400" /> : <ChevronDown size={12} className="text-gray-400" />}
                </button>
            </div>
            {showRec && (
                <div className="absolute right-0 top-full z-50 w-72 max-h-64 overflow-y-auto bg-slate-900 border border-white/10 rounded-b-lg shadow-2xl">
                    <div className="p-2 border-b border-white/10 flex justify-between bg-slate-800/50">
                        <span className="text-xs font-semibold text-gray-300">Game History</span>
                        <button onClick={() => setShowRec(false)}><X size={14} className="text-gray-400" /></button>
                    </div>
                    {records.length === 0 ? (
                        <div className="p-4 text-center text-gray-500 text-xs">No records</div>
                    ) : (
                        <div className="divide-y divide-white/5">
                            {records.map(r => {
                                const net = r.winAmount - r.betAmount;
                                return (
                                    <div key={r.id} className="p-2 flex justify-between text-xs hover:bg-white/5">
                                        <div className="flex items-center gap-2">
                                            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold ${
                                                r.result === 0 ? 'bg-emerald-600' : RED_NUMBERS.has(r.result) ? 'bg-red-600' : 'bg-zinc-800'
                                            }`}>{r.result}</div>
                                            <span className="text-gray-400">{r.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit', second:'2-digit'})}</span>
                                        </div>
                                        <span className={net > 0 ? 'text-emerald-400 font-semibold' : net < 0 ? 'text-red-400' : 'text-gray-500'}>
                                            {net > 0 ? `+$${net}` : net < 0 ? `-$${Math.abs(net)}` : '$0'}
                                        </span>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

// ==========================================
// HISTORY PANEL
// ==========================================
export const HistoryPanel: React.FC<{history: number[]}> = ({ history }) => {
    const last20 = history.slice(0, 20);
    const { hot, cold } = useMemo(() => getHotCold(history), [history]);

    return (
        <div className="w-full bg-slate-900/70 rounded-lg border border-white/10 p-2 sm:p-3 shadow-inner">
            <div className="flex flex-row gap-3">
                {/* Left - Last 20 wrapping */}
                <div className="flex-1 min-w-0">
                    <div className="text-[10px] sm:text-xs text-gray-400 font-semibold mb-1.5 flex items-center gap-1 uppercase tracking-wider">
                        <History size={12} />
                        <span>Recent</span>
                    </div>
                    <div className="flex flex-wrap gap-1 max-h-[60px] overflow-hidden">
                        {last20.length === 0 ? (
                            <span className="text-gray-500 text-[10px]">No draws yet</span>
                        ) : (
                            last20.map((n, i) => (
                                <div 
                                    key={i} 
                                    className={`w-5 h-5 sm:w-6 sm:h-6 shrink-0 rounded-full flex items-center justify-center font-bold text-[8px] sm:text-[10px] border shadow-sm ${
                                        n === 0 ? 'bg-emerald-600 border-emerald-400' : 
                                        RED_NUMBERS.has(n) ? 'bg-red-600 border-red-400' : 'bg-zinc-800 border-zinc-600'
                                    }`}
                                >
                                    {n}
                                </div>
                            ))
                        )}
                    </div>
                </div>

                {/* Divider */}
                <div className="w-px bg-white/10 self-stretch" />

                {/* Right - Hot/Cold stacked */}
                <div className="flex flex-col gap-2 shrink-0">
                    <div>
                        <div className="text-[9px] sm:text-[10px] text-orange-400 font-semibold mb-1 flex items-center gap-1 uppercase tracking-wider">
                            <Flame size={10} />
                            <span>Hot</span>
                        </div>
                        <div className="flex gap-1">
                            {history.length < 10 ? (
                                <span className="text-gray-500 text-[8px]">--</span>
                            ) : (
                                hot.map((n, i) => (
                                    <div 
                                        key={i} 
                                        className={`w-5 h-5 sm:w-6 sm:h-6 shrink-0 rounded-full flex items-center justify-center font-bold text-[8px] sm:text-[10px] border-2 shadow-sm ${
                                            n === 0 ? 'bg-emerald-600 border-orange-400' : 
                                            RED_NUMBERS.has(n) ? 'bg-red-600 border-orange-400' : 'bg-zinc-800 border-orange-400'
                                        }`}
                                    >
                                        {n}
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                    <div>
                        <div className="text-[9px] sm:text-[10px] text-blue-400 font-semibold mb-1 flex items-center gap-1 uppercase tracking-wider">
                            <Snowflake size={10} />
                            <span>Cold</span>
                        </div>
                        <div className="flex gap-1">
                            {history.length < 10 ? (
                                <span className="text-gray-500 text-[8px]">--</span>
                            ) : (
                                cold.map((n, i) => (
                                    <div 
                                        key={i} 
                                        className={`w-5 h-5 sm:w-6 sm:h-6 shrink-0 rounded-full flex items-center justify-center font-bold text-[8px] sm:text-[10px] border-2 shadow-sm ${
                                            n === 0 ? 'bg-emerald-600 border-blue-400' : 
                                            RED_NUMBERS.has(n) ? 'bg-red-600 border-blue-400' : 'bg-zinc-800 border-blue-400'
                                        }`}
                                    >
                                        {n}
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

