import React, { useMemo } from 'react';
import { WHEEL_NUMBERS } from '../constants';
import { getNumberColor, RED_NUMBERS } from '../utils';

const RouletteWheel3D: React.FC<{rotation: number; lastNumber: number | null}> = ({ rotation, lastNumber }) => {
    const segments = useMemo(() => 
        WHEEL_NUMBERS.map((num, i) => ({ 
            num, 
            angle: i * (360 / 37), 
            color: getNumberColor(num) 
        })), 
    []);

    return (
        <div className="relative flex items-center justify-center my-4" style={{ perspective: '800px' }}>
            {/* Outer wooden frame - thin */}
            <div 
                className="absolute w-[240px] h-[240px] sm:w-[300px] sm:h-[300px] lg:w-[380px] lg:h-[380px] rounded-full shadow-[0_20px_50px_rgba(0,0,0,0.8)]" 
                style={{ transform: 'rotateX(20deg)', background: 'linear-gradient(to bottom, #78350f, #451a03)' }} 
            />
            {/* Inner wooden ring - tighter */}
            <div 
                className="absolute w-[230px] h-[230px] sm:w-[288px] sm:h-[288px] lg:w-[366px] lg:h-[366px] rounded-full border-4 border-[#5d2606]" 
                style={{ transform: 'rotateX(20deg)', background: 'linear-gradient(to bottom, #92400e, #78350f)' }} 
            />
            {/* Chrome rim */}
            <div 
                className="absolute w-[222px] h-[222px] sm:w-[278px] sm:h-[278px] lg:w-[354px] lg:h-[354px] rounded-full shadow-inner" 
                style={{ transform: 'rotateX(20deg)', background: 'linear-gradient(135deg, #e5e7eb 0%, #9ca3af 50%, #4b5563 100%)' }} 
            />
            {/* Ball track */}
            <div 
                className="absolute w-[216px] h-[216px] sm:w-[270px] sm:h-[270px] lg:w-[344px] lg:h-[344px] rounded-full shadow-[inset_0_2px_4px_rgba(0,0,0,0.5)]" 
                style={{ transform: 'rotateX(20deg)', background: 'conic-gradient(from 180deg, #27272a, #18181b)' }} 
            />

            {/* Main Wheel */}
            <div className="relative w-[200px] h-[200px] sm:w-[250px] sm:h-[250px] lg:w-[320px] lg:h-[320px]" style={{ transform: 'rotateX(20deg)' }}>
                <div 
                    className="absolute inset-0 rounded-full overflow-hidden shadow-2xl" 
                    style={{ transform: `rotate(${rotation}deg)`, transition: 'transform 4s cubic-bezier(0.15, 0.6, 0.2, 1)' }}
                >
                    <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-xl">
                        <defs>
                            <linearGradient id="gld" x1="0%" y1="0%" x2="0%" y2="100%">
                                <stop offset="0%" stopColor="#fcd34d" />
                                <stop offset="100%" stopColor="#b45309" />
                            </linearGradient>
                            <radialGradient id="cone" cx="50%" cy="50%" r="50%">
                                <stop offset="0%" stopColor="#b45309" />
                                <stop offset="100%" stopColor="#451a03" />
                            </radialGradient>
                        </defs>

                        {/* Wheel segments */}
                        {segments.map((seg, i) => {
                            // Calculating path for each wedge
                            const a1 = (i * 360 / 37 - 360 / 74 - 90) * Math.PI / 180;
                            const a2 = (i * 360 / 37 + 360 / 74 - 90) * Math.PI / 180;
                            const r1 = 48, r2 = 26;
                            const path = `M ${50 + r1 * Math.cos(a1)} ${50 + r1 * Math.sin(a1)} A ${r1} ${r1} 0 0 1 ${50 + r1 * Math.cos(a2)} ${50 + r1 * Math.sin(a2)} L ${50 + r2 * Math.cos(a2)} ${50 + r2 * Math.sin(a2)} A ${r2} ${r2} 0 0 0 ${50 + r2 * Math.cos(a1)} ${50 + r2 * Math.sin(a1)} Z`;

                            // Text position
                            const ta = i * 360 / 37 - 90;
                            const textRadius = 42;
                            const tx = 50 + textRadius * Math.cos(ta * Math.PI / 180);
                            const ty = 50 + textRadius * Math.sin(ta * Math.PI / 180);

                            let fill = '#1a1a1a';
                            if (seg.color === 'green') fill = '#059669';
                            if (seg.color === 'red') fill = '#dc2626';

                            return (
                                <g key={seg.num}>
                                    <path d={path} fill={fill} stroke="#171717" strokeWidth="0.2" />
                                    {/* Gold separators */}
                                    <line x1={50 + r1 * Math.cos(a1)} y1={50 + r1 * Math.sin(a1)} x2={50 + r2 * Math.cos(a1)} y2={50 + r2 * Math.sin(a1)} stroke="url(#gld)" strokeWidth="0.5" />
                                    <text x={tx} y={ty} fill="white" fontSize="5" fontWeight="900" textAnchor="middle" dominantBaseline="middle" transform={`rotate(${i * 360 / 37}, ${tx}, ${ty})`} style={{textShadow: '0px 1px 1px rgba(0,0,0,0.8)'}}>
                                        {seg.num}
                                    </text>
                                </g>
                            );
                        })}

                        {/* Inner cone */}
                        <circle cx="50" cy="50" r="26" fill="url(#cone)" stroke="url(#gld)" strokeWidth="1" />
                        {/* Center hub */}
                        <circle cx="50" cy="50" r="14" fill="#1a1a2e" stroke="url(#gld)" strokeWidth="1.5" />
                        <circle cx="50" cy="50" r="8" fill="#d4af37" />
                        <circle cx="50" cy="50" r="5" fill="#451a03" />
                    </svg>
                </div>
            </div>

            {/* Pointer Pin */}
            <div className="absolute top-0 left-1/2 z-30 drop-shadow-md" style={{ transform: 'translateX(-50%) rotateX(20deg) translateY(4px)' }}>
                <div className="w-0 h-0 border-l-[6px] border-l-transparent border-r-[6px] border-r-transparent border-t-[14px] border-t-yellow-400 filter drop-shadow" />
            </div>

            {/* Result display overlay */}
            {lastNumber !== null && (
                <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
                    <div 
                        className={`text-6xl sm:text-7xl font-black animate-bounce ${
                            lastNumber === 0 ? 'text-emerald-400' : RED_NUMBERS.has(lastNumber) ? 'text-red-500' : 'text-white'
                        }`} 
                        style={{ textShadow: '0 0 40px rgba(0,0,0,0.9), 0 0 10px currentColor' }}
                    >
                        {lastNumber}
                    </div>
                </div>
            )}
        </div>
    );
};

