                                        <span className={net > 0 ? 'text-emerald-400 font-semibold' : net < 0 ? 'text-red-400' : 'text-gray-500'}>
                                            {net > 0 ? `+$${net}` : net < 0 ? `-$${Math.abs(net)}` : '$0'}
                                        </span>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

