// ==========================================
// CASINO CHIP
// ==========================================
export const CasinoChip: React.FC<ChipProps> = ({ value, className = "", size = "md" }) => {
    const sizeClasses = {
        xs: "w-4 h-4 text-[6px] ring-1",
        sm: "w-5 h-5 text-[8px] ring-1",
        md: "w-8 h-8 text-[10px] ring-2",
        lg: "w-12 h-12 text-sm ring-[3px]",
        board: "w-4 h-4 text-[6px] ring-1 sm:w-5 sm:h-5 sm:text-[7px]",
        selector: "w-8 h-8 text-[9px] ring-2 sm:w-10 sm:h-10 sm:text-[10px] md:w-12 md:h-12 md:text-xs"
    };
    const currentSizeClass = sizeClasses[size] || sizeClasses.md;
    const colorClass = getChipColor(value);
    return (
        <div className={`${currentSizeClass} rounded-full flex items-center justify-center font-bold shadow-lg relative ${colorClass} ${className} transition-transform select-none ring-white/30`}>
            <div className="absolute inset-[15%] border border-dashed border-current opacity-40 rounded-full"></div>
            <span className="relative z-10">{value}</span>
        </div>
    );
};

