            // Record Game
            setRecords(prev => [{
                id: Date.now(),
                result: lastNum,
                betAmount: betTotal,
                winAmount: winAmount,
                timestamp: new Date()
            }, ...prev]);

            // Auto Reset after result display
            const timer = setTimeout(() => {
                setPhase('betting');
                setLastNum(null);
                setBets({});
                setBetStack([]);
                setTimeLeft(BETTING_TIME); // Reset Timer
            }, 3500);
            return () => clearTimeout(timer);
        }
    }, [phase, lastNum]); // Only run when phase changes to result

    // Auto-Spin Timer Logic
    useEffect(() => {
