export const ControlPanel: React.FC<{
    chip: number; 
    setChip: (v: number) => void; 
    undo: () => void; 
    clear: () => void; 
    phase: GamePhase; 
    hasBets: boolean;
    timeLeft: number;
    maxTime: number;
    className?: string;
}> = ({ chip, setChip, undo, clear, phase, hasBets, timeLeft, maxTime, className = "" }) => (
    <div className={`flex flex-col gap-1 w-full max-w-xl mx-auto ${className}`}>
        {/* Timer Bar */}
        <div className="flex items-end justify-between px-2 pb-0.5">
            <span className={`text-[10px] font-black uppercase tracking-widest ${phase === 'betting' ? 'text-amber-400' : 'text-slate-500'}`}>
                {phase === 'betting' ? 'Place Your Bets' : phase === 'spinning' ? 'No More Bets' : 'Winning Number'}
            </span>
            <div className="flex items-center gap-1 text-[10px] font-mono text-gray-400">
                <Clock size={10} />
                <span>{phase === 'betting' ? `${timeLeft}s` : '--'}</span>
            </div>
        </div>
        <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden mb-1 relative border border-white/5">
            <div 
                className={`h-full transition-all duration-1000 ease-linear ${
                    phase === 'betting' ? (timeLeft <= 3 ? 'bg-red-500' : 'bg-amber-500') : 'bg-slate-700 w-0'
                }`} 
                style={{width: phase === 'betting' ? `${(timeLeft/maxTime)*100}%` : '0%'}} 
            />
        </div>

        {/* Controls - Icon Only for Better Mobile Fit */}
        <div className="bg-slate-900/95 border border-white/10 rounded-xl p-2 flex items-center gap-2 sm:gap-3 shadow-2xl backdrop-blur-sm relative select-none">

            {/* Clear Button (Left) - Icon Only, High Contrast */}
            <button 
                onClick={() => { clear(); soundManager.playClear(); }} 
                disabled={phase !== 'betting' || !hasBets} 
                className="w-10 h-10 sm:w-12 sm:h-12 rounded-lg sm:rounded-xl bg-red-600 hover:bg-red-500 text-white border border-red-400 shadow-lg flex items-center justify-center shrink-0 transition-all active:scale-95 disabled:opacity-40 disabled:bg-red-950 disabled:border-red-900/50 disabled:text-red-500/50 disabled:shadow-none"
                title="Clear All Bets"
            >
                <Trash2 size={20} strokeWidth={2.5} />
            </button>

            {/* Chips - Centered, Size adjusted for mobile */}
            <div className="flex-1 flex gap-1.5 sm:gap-3 justify-center items-center py-1">
                {CHIP_VALUES.map(v => (
                    <button 
                        key={v} 
                        onClick={() => { setChip(v); soundManager.playChipSelect(); }} 
                        className={`shrink-0 rounded-full transition-all duration-200 ${chip === v ? '-translate-y-2 scale-110 ring-2 ring-yellow-400 shadow-lg shadow-black/50 z-10' : 'opacity-70 hover:opacity-100 hover:scale-105'}`}
                    >
                        <CasinoChip value={v} size="selector" />
                    </button>
                ))}
            </div>

            {/* Undo Button (Right) - Icon Only, High Contrast */}
            <button 
                onClick={() => { undo(); soundManager.playUndo(); }} 
                disabled={phase !== 'betting' || !hasBets} 
                className="w-10 h-10 sm:w-12 sm:h-12 rounded-lg sm:rounded-xl bg-blue-600 hover:bg-blue-500 text-white border border-blue-400 shadow-lg flex items-center justify-center shrink-0 transition-all active:scale-95 disabled:opacity-40 disabled:bg-blue-950 disabled:border-blue-900/50 disabled:text-blue-500/50 disabled:shadow-none"
                title="Undo Last Bet"
            >
                <Undo2 size={20} strokeWidth={2.5} />
            </button>
        </div>
    </div>
);

import React, { useMemo } from 'react';
import { ArrowLeft, Volume2, VolumeX, Bell, ChevronUp, ChevronDown, X, Undo2, Trash2, Play, History, Flame, Snowflake, Monitor, Smartphone, Clock } from 'lucide-react';
import { getChipColor, getHotCold } from '../utils';
