                className="w-8 h-8 sm:w-12 sm:h-12 rounded-full sm:rounded-xl hover:bg-white/10 sm:bg-blue-600 sm:hover:bg-blue-500 text-blue-500 sm:text-white sm:border sm:border-blue-400 sm:shadow-lg flex items-center justify-center shrink-0 transition-all active:scale-95 disabled:opacity-30 disabled:grayscale"
                title="Undo Last Bet"
            >
                <Undo2 strokeWidth={2.5} className="w-5 h-5 sm:w-6 sm:h-6" />
            </button>
        </div>
    </div>
);

import React, { useState, useEffect, useCallback } from 'react';
import { NavBar, LiveFeed, BalanceBar, HistoryPanel, ControlPanel } from './components/UI';
import BettingBoard from './components/BettingBoard';
import RouletteWheel3D from './components/RouletteWheel3D';
import { GamePhase, PlayerBet, BetAction, GameRecord } from './types';
import { WHEEL_NUMBERS, CHIP_VALUES, BOT_NAMES } from './constants';
import { calculateWinnings } from './utils';
import { soundManager } from './services/SoundManager';

const App = () => {
    // View State
    const [viewMode, setViewMode] = useState<'full' | 'mobile'>('full');

    // Game State
    const [balance, setBalance] = useState(1000);
    const [bets, setBets] = useState<Record<string, number>>({});
    const [betStack, setBetStack] = useState<BetAction[]>([]);
    const [phase, setPhase] = useState<GamePhase>('betting');
    const [lastNum, setLastNum] = useState<number | null>(null);
    const [rotation, setRotation] = useState(0);
    const [history, setHistory] = useState<number[]>([]);

    // Auto Spin State
    const BETTING_TIME = 15;
    const [timeLeft, setTimeLeft] = useState(BETTING_TIME);

    // UI State
    const [chip, setChip] = useState(5);
    const [feed, setFeed] = useState<PlayerBet[]>([]);
    const [muted, setMuted] = useState(false);
    const [showRec, setShowRec] = useState(false);
    const [records, setRecords] = useState<GameRecord[]>([]);

    const betTotal = betStack.reduce((s, b) => s + b.amount, 0);
    const SPIN_DURATION = 10000;

    // Simulated Multiplayer Feed
    useEffect(() => {
        const i = setInterval(() => {
            if (Math.random() > 0.4) {
                setFeed(f => [{
                    username: BOT_NAMES[Math.floor(Math.random() * BOT_NAMES.length)],
                    number: String(Math.floor(Math.random() * 37)),
                    amount: CHIP_VALUES[Math.floor(Math.random() * CHIP_VALUES.length)]
                }, ...f].slice(0, 8));
            }
        }, 2500);
        return () => clearInterval(i);
    }, []);

    // Sync Mute State
    useEffect(() => { soundManager.setMuted(muted); }, [muted]);

    const placeBet = (id: string) => {
        if (phase !== 'betting' || balance < chip) return;
        soundManager.playChipPlace();
        setBalance(b => b - chip);
        setBets(b => ({ ...b, [id]: (b[id] || 0) + chip }));
        setBetStack(s => [...s, { id, amount: chip }]);
    };

    const undo = () => {
        if (phase !== 'betting' || !betStack.length) return;
        const last = betStack[betStack.length - 1];
        setBalance(b => b + last.amount);
        setBets(b => {
            const n = { ...b };
            n[last.id] -= last.amount;
            if (n[last.id] <= 0) delete n[last.id];
            return n;
        });
        setBetStack(s => s.slice(0, -1));
    };

    const clear = () => {
        if (phase !== 'betting') return;
        setBalance(b => b + betTotal);
        setBets({});
        setBetStack([]);
    };

    // Memoized spin function to be used in effects
    const spin = useCallback(() => {
        // Allow spin even with 0 bets (Auto spin requirement)
        setPhase('spinning');
        soundManager.playSpinSound(SPIN_DURATION);

        const resultIndex = Math.floor(Math.random() * 37);
        const winningNumber = WHEEL_NUMBERS[resultIndex];

        // Calculate Rotation
        const anglePerItem = 360 / 37;
        const targetAngle = resultIndex * anglePerItem;

        // We use a functional update for rotation to ensure we have the latest value
        setRotation(prevRotation => {
            const currentMod = prevRotation % 360;
            const targetMod = (360 - targetAngle) % 360; 

            let diff = targetMod - currentMod;
            if (diff < 0) diff += 360; 

            const extraSpins = 12 * 360;
            return prevRotation + extraSpins + diff;
        });

        // Resolution
        setTimeout(() => {
            setLastNum(winningNumber);
            setPhase('result');
            setHistory(prev => [winningNumber, ...prev]);

            // We need to calculate winnings based on current bets state
            // Since this runs in a closure, we might need a ref or pass bets, 
            // but for simplicity in this structure we rely on the state being stable during spin phase
            // However, inside setTimeout, state might be stale.
            // A robust way: calculate inside a setState or use a Ref. 
            // For this app size, we'll use the state from the outer scope which 'spin' captures.
            // IMPORTANT: 'spin' needs to be recreated if 'bets' changes, but that resets timer.
            // ideally we use a ref for bets to access latest without re-triggering effects.
        }, SPIN_DURATION);
    }, []); // Removed dependencies to avoid recreating 'spin' constantly. We handle logic below.

    // Handle Winnings and Reset (Post-Spin Logic)
    useEffect(() => {
        if (phase === 'result' && lastNum !== null) {
            const winAmount = calculateWinnings(lastNum, bets);

            if (winAmount > 0) {
                setBalance(b => b + winAmount);
                soundManager.playWin();
            } else {
                soundManager.playLose();
            }

            // Record Game
            setRecords(prev => [{
                id: Date.now(),
                result: lastNum,
                betAmount: betTotal,
                winAmount: winAmount,
                timestamp: new Date()
            }, ...prev]);

            // Auto Reset after result display
            const timer = setTimeout(() => {
                setPhase('betting');
                setLastNum(null);
                setBets({});
                setBetStack([]);
                setTimeLeft(BETTING_TIME); // Reset Timer
            }, 3500);
            return () => clearTimeout(timer);
        }
    }, [phase, lastNum]); // Only run when phase changes to result

    // Auto-Spin Timer Logic
    useEffect(() => {
        let interval: ReturnType<typeof setInterval>;
        if (phase === 'betting') {
            if (timeLeft > 0) {
                interval = setInterval(() => {
                    setTimeLeft(t => Math.max(0, t - 1));
                }, 1000);
            } else {
                // Time is up, trigger spin
                spin();
            }
        }
        return () => clearInterval(interval);
    }, [phase, timeLeft, spin]);

    // Style logic for the main container based on view mode
    const containerClass = viewMode === 'mobile' 
        ? 'relative w-[375px] h-[750px] max-h-[95vh] mx-auto my-auto mt-4 sm:mt-8 border-[8px] border-slate-800 rounded-[3rem] shadow-2xl overflow-hidden bg-[#0f172a] flex flex-col ring-4 ring-black/20'
        : 'fixed inset-0 bg-[#0f172a] text-white flex flex-col overflow-hidden';

    const wrapperClass = viewMode === 'mobile'
        ? 'fixed inset-0 bg-gradient-to-br from-slate-900 to-black flex items-center justify-center overflow-auto p-4'
        : '';

    const isMobile = viewMode === 'mobile';

    return (
        <div className={wrapperClass}>
            <div className={containerClass}>
                <NavBar 
                    onExit={() => window.location.reload()} 
                    isMuted={muted} 
                    setIsMuted={setMuted}
                    viewMode={viewMode}
                    onToggleView={() => setViewMode(v => v === 'full' ? 'mobile' : 'full')}
                />

                <LiveFeed feed={feed} />

                <BalanceBar 
                    balance={balance} 
                    betTotal={betTotal} 
                    records={records}
                    showRec={showRec}
                    setShowRec={setShowRec}
                />

                {/* Main Content Area */}
                <main className={`flex-1 min-h-0 ${isMobile ? 'flex flex-col px-2 pt-2 pb-3 overflow-hidden' : 'flex items-center justify-center p-6 overflow-hidden'}`}>
                    <div className={`w-full mx-auto transition-all duration-500 h-full ${isMobile ? 'flex flex-col justify-between' : 'flex flex-row items-center justify-center gap-12 max-w-7xl'}`}>

                        {/* Wheel Section */}
                        <div className={`flex flex-col items-center justify-center ${isMobile ? 'shrink-0 scale-[0.6] -my-10 h-[200px]' : 'flex-1 max-w-[450px]'}`}>
                             <div className={!isMobile ? 'scale-110 mb-8' : ''}>
                                <RouletteWheel3D rotation={rotation} lastNumber={lastNum} spinDuration={SPIN_DURATION} />
                             </div>

                             {!isMobile && (
                                 <div className="w-full mt-8">
                                     <HistoryPanel history={history} />
                                 </div>
                             )}
                        </div>

                        {/* Betting Board Section + Controls */}
                        <div className={`flex flex-col items-center justify-center gap-2 ${isMobile ? 'w-full shrink-0 z-10 flex-1 min-h-0' : 'flex-[1.5] w-full max-w-[900px]'}`}>
                             {/* Mobile History Panel moved here */}
                             {isMobile && (
                                <div className="w-full mb-1">
                                    <HistoryPanel history={history} />
                                </div>
                             )}

                             <BettingBoard bets={bets} onBet={placeBet} phase={phase} />

                             {/* Control Panel with Auto-Spin Timer */}
                             <div className="w-full shrink-0 px-1 sm:px-0">
                                <ControlPanel 
                                    chip={chip} 
                                    setChip={setChip} 
                                    undo={undo} 
                                    clear={clear} 
                                    phase={phase}
                                    hasBets={betTotal > 0}
                                    timeLeft={timeLeft}
                                    maxTime={BETTING_TIME}
                                />
                             </div>
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
};

export default App;

import React, { useMemo } from 'react';
import { WHEEL_NUMBERS, RED_NUMBERS } from '../constants';
import { getNumberColor } from '../utils';

const RouletteWheel3D: React.FC<{rotation: number; lastNumber: number | null; spinDuration?: number}> = ({ rotation, lastNumber, spinDuration = 4000 }) => {
    const segments = useMemo(() => 
        WHEEL_NUMBERS.map((num, i) => ({ 
            num, 
            angle: i * (360 / 37), 
            color: getNumberColor(num) 
        })), 
    []);

    return (
        <div className="relative flex items-center justify-center" style={{ perspective: '800px' }}>
            {/* Outer wooden frame - thin */}
            <div 
                className="absolute w-[240px] h-[240px] sm:w-[300px] sm:h-[300px] lg:w-[380px] lg:h-[380px] rounded-full shadow-[0_20px_50px_rgba(0,0,0,0.8)]" 
                style={{ transform: 'rotateX(20deg)', background: 'linear-gradient(to bottom, #78350f, #451a03)' }} 
            />
            {/* Inner wooden ring - tighter */}
            <div 
                className="absolute w-[230px] h-[230px] sm:w-[288px] sm:h-[288px] lg:w-[366px] lg:h-[366px] rounded-full border-4 border-[#5d2606]" 
                style={{ transform: 'rotateX(20deg)', background: 'linear-gradient(to bottom, #92400e, #78350f)' }} 
            />
            {/* Chrome rim */}
            <div 
                className="absolute w-[222px] h-[222px] sm:w-[278px] sm:h-[278px] lg:w-[354px] lg:h-[354px] rounded-full shadow-inner" 
                style={{ transform: 'rotateX(20deg)', background: 'linear-gradient(135deg, #e5e7eb 0%, #9ca3af 50%, #4b5563 100%)' }} 
            />
            {/* Ball track */}
            <div 
                className="absolute w-[216px] h-[216px] sm:w-[270px] sm:h-[270px] lg:w-[344px] lg:h-[344px] rounded-full shadow-[inset_0_2px_4px_rgba(0,0,0,0.5)]" 
                style={{ transform: 'rotateX(20deg)', background: 'conic-gradient(from 180deg, #27272a, #18181b)' }} 
            />

            {/* Main Wheel */}
            <div className="relative w-[200px] h-[200px] sm:w-[250px] sm:h-[250px] lg:w-[320px] lg:h-[320px]" style={{ transform: 'rotateX(20deg)' }}>
                <div 
                    className="absolute inset-0 rounded-full overflow-hidden shadow-2xl" 
                    style={{ transform: `rotate(${rotation}deg)`, transition: `transform ${spinDuration}ms cubic-bezier(0.15, 0.6, 0.2, 1)` }}
                >
                    <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-xl">
                        <defs>
                            <linearGradient id="gld" x1="0%" y1="0%" x2="0%" y2="100%">
                                <stop offset="0%" stopColor="#fcd34d" />
                                <stop offset="100%" stopColor="#b45309" />
                            </linearGradient>
                            <radialGradient id="cone" cx="50%" cy="50%" r="50%">
                                <stop offset="0%" stopColor="#b45309" />
                                <stop offset="100%" stopColor="#451a03" />
                            </radialGradient>
                        </defs>

                        {/* Wheel segments */}
                        {segments.map((seg, i) => {
                            // Calculating path for each wedge
                            const a1 = (i * 360 / 37 - 360 / 74 - 90) * Math.PI / 180;
                            const a2 = (i * 360 / 37 + 360 / 74 - 90) * Math.PI / 180;
                            const r1 = 48, r2 = 26;
                            const path = `M ${50 + r1 * Math.cos(a1)} ${50 + r1 * Math.sin(a1)} A ${r1} ${r1} 0 0 1 ${50 + r1 * Math.cos(a2)} ${50 + r1 * Math.sin(a2)} L ${50 + r2 * Math.cos(a2)} ${50 + r2 * Math.sin(a2)} A ${r2} ${r2} 0 0 0 ${50 + r2 * Math.cos(a1)} ${50 + r2 * Math.sin(a1)} Z`;

                            // Text position
                            const ta = i * 360 / 37 - 90;
                            const textRadius = 42;
                            const tx = 50 + textRadius * Math.cos(ta * Math.PI / 180);
                            const ty = 50 + textRadius * Math.sin(ta * Math.PI / 180);

                            let fill = '#1a1a1a';
                            if (seg.color === 'green') fill = '#059669';
                            if (seg.color === 'red') fill = '#dc2626';

                            return (
                                <g key={seg.num}>
                                    <path d={path} fill={fill} stroke="#171717" strokeWidth="0.2" />
                                    {/* Gold separators */}
                                    <line x1={50 + r1 * Math.cos(a1)} y1={50 + r1 * Math.sin(a1)} x2={50 + r2 * Math.cos(a1)} y2={50 + r2 * Math.sin(a1)} stroke="url(#gld)" strokeWidth="0.5" />
                                    <text x={tx} y={ty} fill="white" fontSize="5" fontWeight="900" textAnchor="middle" dominantBaseline="middle" transform={`rotate(${i * 360 / 37}, ${tx}, ${ty})`} style={{textShadow: '0px 1px 1px rgba(0,0,0,0.8)'}}>
                                        {seg.num}
                                    </text>
                                </g>
                            );
                        })}

                        {/* Inner circle with text */}
                        <circle cx="50" cy="50" r="26" fill="#18181b" stroke="url(#gld)" strokeWidth="1" />
                        <text 
                            x="50" 
                            y="50" 
                            fill="#d4af37" 
                            fontSize="6" 
                            fontWeight="700" 
                            textAnchor="middle" 
                            dominantBaseline="middle"
                            style={{ textShadow: '0 1px 2px rgba(0,0,0,0.8)', letterSpacing: '0.5px' }}
                        >
                            Randseed
                        </text>
                    </svg>
                </div>
            </div>

            {/* Pointer Pin */}
            <div className="absolute top-0 left-1/2 z-30 drop-shadow-md" style={{ transform: 'translateX(-50%) rotateX(20deg) translateY(4px)' }}>
                <div className="w-0 h-0 border-l-[6px] border-l-transparent border-r-[6px] border-r-transparent border-t-[14px] border-t-yellow-400 filter drop-shadow" />
            </div>

            {/* Result display overlay */}
            {lastNumber !== null && (
                <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
                    <div 
                        className={`text-6xl sm:text-7xl font-black animate-bounce ${
                            lastNumber === 0 ? 'text-emerald-400' : RED_NUMBERS.has(lastNumber) ? 'text-red-500' : 'text-white'
                        }`} 
                        style={{ textShadow: '0 0 40px rgba(0,0,0,0.9), 0 0 10px currentColor' }}
                    >
                        {lastNumber}
                    </div>
                </div>
            )}
        </div>
    );
};

