class SoundManager {
    private ctx: AudioContext | null = null;
    private gain: GainNode | null = null;
    private muted = false;

    private init() {
        if (!this.ctx) {
            this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
            this.gain = this.ctx.createGain();
            this.gain.connect(this.ctx.destination);
        }
        if (this.ctx.state === 'suspended') this.ctx.resume();
    }

    setMuted(m: boolean) {
        this.muted = m;
        if (this.gain) this.gain.gain.value = m ? 0 : 1;
    }

    playChipSelect() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const o = this.ctx.createOscillator();
        const g = this.ctx.createGain();
        o.connect(g);
        g.connect(this.gain);
        o.frequency.setValueAtTime(1800, this.ctx.currentTime);
        o.frequency.exponentialRampToValueAtTime(1200, this.ctx.currentTime + 0.03);
        g.gain.setValueAtTime(0.2, this.ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.06);
        o.start();
        o.stop(this.ctx.currentTime + 0.06);
    }

    playChipPlace() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const now = this.ctx.currentTime;

        // Ceramic click
        const o1 = this.ctx.createOscillator();
        const g1 = this.ctx.createGain();
        const f1 = this.ctx.createBiquadFilter();
        o1.connect(f1);
        f1.connect(g1);
        g1.connect(this.gain);
        o1.type = 'triangle';
        o1.frequency.setValueAtTime(2800, now);
        o1.frequency.exponentialRampToValueAtTime(1200, now + 0.04);
        f1.type = 'bandpass';
        f1.frequency.value = 2000;
        f1.Q.value = 2;
        g1.gain.setValueAtTime(0.3, now);
        g1.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
        o1.start();
        o1.stop(now + 0.1);

        // Thump
        const o2 = this.ctx.createOscillator();
        const g2 = this.ctx.createGain();
        o2.connect(g2);
        g2.connect(this.gain);
        o2.frequency.setValueAtTime(150, now);
        o2.frequency.exponentialRampToValueAtTime(60, now + 0.08);
        g2.gain.setValueAtTime(0.25, now);
        g2.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
        o2.start();
        o2.stop(now + 0.1);
    }

    // Synchronized spin sound - takes duration parameter
    playSpinSound(duration = 4000) {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;

        const now = this.ctx.currentTime;
        const dur = duration / 1000;

        // Ball clicks - start fast, slow down (no scratching/friction)
        let t = 0;
        let interval = 0.04;
        // Increased iteration limit from 50 to 200 to support longer durations (10s+)
        for (let i = 0; i < 200 && t < dur - 0.5; i++) {
            const ct = now + t;
            const prog = t / dur;
            const o = this.ctx.createOscillator();
            const g = this.ctx.createGain();
            o.connect(g);
            g.connect(this.gain);
            o.frequency.setValueAtTime(1800 - prog * 800 + Math.random() * 200, ct);
            o.frequency.exponentialRampToValueAtTime(900, ct + 0.015);
            g.gain.setValueAtTime(0.15 * (1 - prog * 0.3), ct);
            g.gain.exponentialRampToValueAtTime(0.01, ct + 0.025);
            o.start(ct);
            o.stop(ct + 0.03);
            t += interval;
            interval *= 1.06; // Slow down
        }

        // Ball drop bounces - plays at end of spin
        const dropTime = now + dur - 0.4;
        const bounces = [
            { delay: 0, freq: 800, vol: 0.35 },
            { delay: 0.1, freq: 700, vol: 0.28 },
            { delay: 0.17, freq: 650, vol: 0.22 },
            { delay: 0.23, freq: 600, vol: 0.16 },
            { delay: 0.28, freq: 550, vol: 0.12 }
        ];

        bounces.forEach(({ delay, freq, vol }) => {
            const o = this.ctx!.createOscillator();
            const g = this.ctx!.createGain();
            o.connect(g);
            g.connect(this.gain!);
            o.frequency.setValueAtTime(freq, dropTime + delay);
            o.frequency.exponentialRampToValueAtTime(freq * 0.6, dropTime + delay + 0.06);
            g.gain.setValueAtTime(vol, dropTime + delay);
            g.gain.exponentialRampToValueAtTime(0.01, dropTime + delay + 0.08);
            o.start(dropTime + delay);
            o.stop(dropTime + delay + 0.08);
        });

        // Gentle suspense tone
        const so = this.ctx.createOscillator();
        const sg = this.ctx.createGain();
        so.connect(sg);
        sg.connect(this.gain);
        so.frequency.setValueAtTime(60, now);
        so.frequency.linearRampToValueAtTime(80, now + dur * 0.7);
        so.frequency.linearRampToValueAtTime(50, now + dur);
        sg.gain.setValueAtTime(0.03, now);
        sg.gain.linearRampToValueAtTime(0.08, now + dur * 0.8);
        sg.gain.linearRampToValueAtTime(0.01, now + dur);
        so.start(now);
        so.stop(now + dur);
    }

    playWin() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const now = this.ctx.currentTime;
        const notes = [523.25, 659.25, 783.99, 1046.50, 1318.51];
        notes.forEach((f, i) => {
            const o = this.ctx!.createOscillator();
            const g = this.ctx!.createGain();
            o.connect(g);
            g.connect(this.gain!);
            o.frequency.value = f;
            g.gain.setValueAtTime(0.25, now + i * 0.08);
            g.gain.exponentialRampToValueAtTime(0.01, now + i * 0.08 + 0.5);
            o.start(now + i * 0.08);
            o.stop(now + i * 0.08 + 0.5);
        });
    }

    playLose() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const o = this.ctx.createOscillator();
        const g = this.ctx.createGain();
        o.connect(g);
        g.connect(this.gain);
        o.frequency.setValueAtTime(350, this.ctx.currentTime);
        o.frequency.exponentialRampToValueAtTime(120, this.ctx.currentTime + 0.6);
        g.gain.setValueAtTime(0.15, this.ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.6);
        o.start();
        o.stop(this.ctx.currentTime + 0.6);
    }

    playUndo() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const o = this.ctx.createOscillator();
        const g = this.ctx.createGain();
        o.connect(g);
        g.connect(this.gain);
        o.frequency.setValueAtTime(800, this.ctx.currentTime);
        o.frequency.exponentialRampToValueAtTime(400, this.ctx.currentTime + 0.12);
        g.gain.setValueAtTime(0.2, this.ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.12);
        o.start();
        o.stop(this.ctx.currentTime + 0.12);
    }

    playClear() {
        if (this.muted) return;
        this.init();
        if (!this.ctx || !this.gain) return;
        const o = this.ctx.createOscillator();
        const g = this.ctx.createGain();
        o.connect(g);
        g.connect(this.gain);
        o.frequency.setValueAtTime(600, this.ctx.currentTime);
        o.frequency.exponentialRampToValueAtTime(300, this.ctx.currentTime + 0.15);
        g.gain.setValueAtTime(0.15, this.ctx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.15);
        o.start();
        o.stop(this.ctx.currentTime + 0.15);
    }
}

export const soundManager = new SoundManager();

import React from 'react';
import { GamePhase } from '../types';
import { RED_NUMBERS } from '../constants';
import { getBetNumbers } from '../utils';
import { CasinoChip } from './UI';

// Position constants specifically for the board layout
const CHIP_POSITIONS: Record<string, {left: string; top: string}> = {
    '0': { left: '3.57%', top: '30%' },
    'row3': { left: '96.43%', top: '10%' },
    'row2': { left: '96.43%', top: '30%' },
    'row1': { left: '96.43%', top: '50%' },
    '1st12': { left: '28.57%', top: '70%' },
    '2nd12': { left: '50%', top: '70%' },
    '3rd12': { left: '71.43%', top: '70%' },
    '1-18': { left: '17.86%', top: '90%' },
    'EVEN': { left: '32.14%', top: '90%' },
    'RED': { left: '46.43%', top: '90%' },
    'BLACK': { left: '60.71%', top: '90%' },
    'ODD': { left: '75%', top: '90%' },
    '19-36': { left: '89.29%', top: '90%' },
    '0_1': { left: '7.14%', top: '50%' },
    '0_2': { left: '7.14%', top: '30%' },
    '0_3': { left: '7.14%', top: '10%' },
    '0_1_2': { left: '7.14%', top: '40%' },
    '0_2_3': { left: '7.14%', top: '20%' },
    '0_1_2_3': { left: '7.14%', top: '55%' },
};

const BettingBoard: React.FC<{bets: Record<string, number>; onBet: (id: string) => void; phase: GamePhase}> = ({ bets, onBet, phase }) => {
    const colW = 100 / 14;
    const rowH = 20;
    const bet = (id: string) => phase === 'betting' && onBet(id);

    const getChipPosition = (key: string): {left: string; top: string} => {
        if (CHIP_POSITIONS[key]) return CHIP_POSITIONS[key];
        const nums = getBetNumbers(key);
        if (nums.length === 0) return { left: '50%', top: '50%' };
        let totalLeft = 0, totalTop = 0;
        nums.forEach(n => {
            if (n === 0) { totalLeft += 3.57; totalTop += 30; } 
            else {
                const col = Math.ceil(n / 3);
                const row = n % 3 === 0 ? 0 : (3 - (n % 3));
                totalLeft += colW * (col + 0.5);
                totalTop += row * rowH + 10;
            }
        });
        if (nums.length === 3 && !nums.includes(0)) {
            const sorted = [...nums].sort((a, b) => a - b);
            if (sorted[0] >= 1 && sorted[2] - sorted[0] === 2) {
                return { left: `${totalLeft / 3}%`, top: '58%' };
            }
        }
        return { left: `${totalLeft / nums.length}%`, top: `${totalTop / nums.length}%` };
    };

    const rowTop = [3, 6, 9, 12, 15, 18, 21, 24, 27, 30, 33, 36];
    const rowMid = [2, 5, 8, 11, 14, 17, 20, 23, 26, 29, 32, 35];
    const rowBot = [1, 4, 7, 10, 13, 16, 19, 22, 25, 28, 31, 34];

    // Standard Casino Colors
    const COLOR_RED = 'bg-[#D92D28]';
    const COLOR_BLACK = 'bg-[#1F2633]';
    const COLOR_GREEN = 'bg-[#0C5C30]';
    const COLOR_HOVER = 'hover:brightness-125';

    return (
        <div className="w-full relative select-none">
            {/* Aspect ratio tuned for layout */}
            <div className="w-full aspect-[14/8] sm:aspect-[14/6] bg-[#0f172a] rounded-lg shadow-2xl ring-4 ring-slate-800 transition-all duration-300">
                <div className="w-full h-full grid grid-cols-[1fr_repeat(12,1fr)_1fr] grid-rows-5 rounded-lg overflow-hidden border-2 border-slate-700/50">

                    {/* Zero */}
                    <div className={`${COLOR_GREEN} border-r-2 border-slate-900/50 flex items-center justify-center text-white font-bold cursor-pointer ${COLOR_HOVER} active:scale-95 transition-all`} style={{gridColumn:'1',gridRow:'1/4'}} onClick={()=>bet('0')}><span className="-rotate-90 sm:rotate-0 text-lg shadow-sm">0</span></div>

                    {/* Numbers Grid */}
                    {rowTop.map((n,i)=><div key={n} className={`${RED_NUMBERS.has(n)? COLOR_RED : COLOR_BLACK} border-r border-b border-slate-900/30 flex items-center justify-center text-white font-bold text-[10px] sm:text-sm cursor-pointer ${COLOR_HOVER} transition-all`} style={{gridColumn:i+2,gridRow:1}} onClick={()=>bet(n.toString())}>{n}</div>)}
                    {rowMid.map((n,i)=><div key={n} className={`${RED_NUMBERS.has(n)? COLOR_RED : COLOR_BLACK} border-r border-b border-slate-900/30 flex items-center justify-center text-white font-bold text-[10px] sm:text-sm cursor-pointer ${COLOR_HOVER} transition-all`} style={{gridColumn:i+2,gridRow:2}} onClick={()=>bet(n.toString())}>{n}</div>)}
                    {rowBot.map((n,i)=><div key={n} className={`${RED_NUMBERS.has(n)? COLOR_RED : COLOR_BLACK} border-r border-slate-900/30 flex items-center justify-center text-white font-bold text-[10px] sm:text-sm cursor-pointer ${COLOR_HOVER} transition-all`} style={{gridColumn:i+2,gridRow:3}} onClick={()=>bet(n.toString())}>{n}</div>)}

                    {/* 2:1 Labels */}
                    {['row3','row2','row1'].map((k,i)=><div key={k} className="bg-transparent border-b border-slate-700/50 flex items-center justify-center text-slate-300 font-bold text-[8px] sm:text-xs cursor-pointer hover:bg-white/5 transition-colors" style={{gridColumn:14,gridRow:i+1}} onClick={()=>bet(k)}>2:1</div>)}

                    {/* Dozens */}
                    <div className="bg-transparent border-r border-b border-slate-700/50 flex items-center justify-center text-slate-300 font-bold text-[8px] sm:text-xs cursor-pointer hover:bg-white/5 transition-colors" style={{gridColumn:'2/6',gridRow:4}} onClick={()=>bet('1st12')}>1st 12</div>
                    <div className="bg-transparent border-r border-b border-slate-700/50 flex items-center justify-center text-slate-300 font-bold text-[8px] sm:text-xs cursor-pointer hover:bg-white/5 transition-colors" style={{gridColumn:'6/10',gridRow:4}} onClick={()=>bet('2nd12')}>2nd 12</div>
                    <div className="bg-transparent border-r border-b border-slate-700/50 flex items-center justify-center text-slate-300 font-bold text-[8px] sm:text-xs cursor-pointer hover:bg-white/5 transition-colors" style={{gridColumn:'10/14',gridRow:4}} onClick={()=>bet('3rd12')}>3rd 12</div>

                    {/* Bottom Bets */}
                    <div className="bg-transparent border-r border-slate-700/50 flex items-center justify-center text-slate-300 font-bold text-[8px] sm:text-xs cursor-pointer hover:bg-white/5 transition-colors" style={{gridColumn:'2/4',gridRow:5}} onClick={()=>bet('1-18')}>1-18</div>
                    <div className="bg-transparent border-r border-slate-700/50 flex items-center justify-center text-slate-300 font-bold text-[8px] sm:text-xs cursor-pointer hover:bg-white/5 transition-colors" style={{gridColumn:'4/6',gridRow:5}} onClick={()=>bet('EVEN')}>EVEN</div>
                    <div className="bg-transparent border-r border-slate-700/50 flex items-center justify-center cursor-pointer hover:bg-white/5 transition-colors" style={{gridColumn:'6/8',gridRow:5}} onClick={()=>bet('RED')}><div className={`w-8 h-5 sm:w-12 sm:h-8 ${COLOR_RED} rounded-sm shadow-sm flex items-center justify-center text-[8px] sm:text-[10px] text-white font-bold`}>RED</div></div>
                    <div className="bg-transparent border-r border-slate-700/50 flex items-center justify-center cursor-pointer hover:bg-white/5 transition-colors" style={{gridColumn:'8/10',gridRow:5}} onClick={()=>bet('BLACK')}><div className={`w-8 h-5 sm:w-12 sm:h-8 ${COLOR_BLACK} rounded-sm border border-slate-600 shadow-sm flex items-center justify-center text-[8px] sm:text-[10px] text-white font-bold`}>BLACK</div></div>
                    <div className="bg-transparent border-r border-slate-700/50 flex items-center justify-center text-slate-300 font-bold text-[8px] sm:text-xs cursor-pointer hover:bg-white/5 transition-colors" style={{gridColumn:'10/12',gridRow:5}} onClick={()=>bet('ODD')}>ODD</div>
                    <div className="bg-transparent flex items-center justify-center text-slate-300 font-bold text-[8px] sm:text-xs cursor-pointer hover:bg-white/5 transition-colors" style={{gridColumn:'12/14',gridRow:5}} onClick={()=>bet('19-36')}>19-36</div>
                </div>
            </div>

            {/* Click handlers for split bets */}
            {/* Horizontal Splits */}
            {[0,1].map(rg=>Array.from({length:12},(_,c)=>{const col=c+1,t=col*3-(rg===0?0:1),b=col*3-(rg===0?1:2),id=`${Math.min(t,b)}_${Math.max(t,b)}`;return<div key={`hs${rg}${c}`} className="absolute cursor-pointer hover:bg-yellow-400/30 rounded-sm z-10" style={{left:`calc(${colW*(col+0.5)}% - 12px)`,top:`calc(${(rg+1)*rowH}% - 6px)`,width:'24px',height:'12px'}} onClick={()=>bet(id)}/>;}))}
            {/* Vertical Splits */}
            {[0,1,2].map(r=>Array.from({length:11},(_,c)=>{const col=c+1,l=col*3-(r===0?0:r===1?1:2),rt=(col+1)*3-(r===0?0:r===1?1:2),id=`${Math.min(l,rt)}_${Math.max(l,rt)}`;return<div key={`vs${r}${c}`} className="absolute cursor-pointer hover:bg-yellow-400/30 rounded-sm z-10" style={{left:`calc(${colW*(col+1)}% - 6px)`,top:`calc(${r*rowH+rowH/2}% - 12px)`,width:'12px',height:'24px'}} onClick={()=>bet(id)}/>;}))}
            {/* Corners */}
            {[0,1].map(rg=>Array.from({length:11},(_,c)=>{const col=c+1,tl=col*3-(rg===0?0:1),tr=(col+1)*3-(rg===0?0:1),bl=col*3-(rg===0?1:2),br=(col+1)*3-(rg===0?1:2),nums=[tl,tr,bl,br].sort((a,b)=>a-b),id=nums.join('_');return<div key={`cr${rg}${c}`} className="absolute cursor-pointer hover:bg-blue-400/30 rounded-full z-20" style={{left:`calc(${colW*(col+1)}% - 8px)`,top:`calc(${(rg+1)*rowH}% - 8px)`,width:'16px',height:'16px'}} onClick={()=>bet(id)}/>;}))}
            {/* Streets (rows of 3) - trigger at bottom of cell */}
            {Array.from({length:12},(_,c)=>{const col=c+1,id=`${(col-1)*3+1}_${(col-1)*3+2}_${(col-1)*3+3}`;return<div key={`st${c}`} className="absolute cursor-pointer hover:bg-purple-400/30 rounded-sm z-10" style={{left:`calc(${colW*(col+0.5)}% - 14px)`,top:'calc(60% - 7px)',width:'28px',height:'14px'}} onClick={()=>bet(id)}/>;}).flat()}

            {/* Zero special bets */}
            <div className="absolute cursor-pointer hover:bg-yellow-400/30 rounded-sm z-10" style={{left:`calc(${colW}% - 6px)`,top:'calc(50% - 12px)',width:'12px',height:'24px'}} onClick={()=>bet('0_1')}/>
            <div className="absolute cursor-pointer hover:bg-yellow-400/30 rounded-sm z-10" style={{left:`calc(${colW}% - 6px)`,top:'calc(30% - 12px)',width:'12px',height:'24px'}} onClick={()=>bet('0_2')}/>
            <div className="absolute cursor-pointer hover:bg-yellow-400/30 rounded-sm z-10" style={{left:`calc(${colW}% - 6px)`,top:'calc(10% - 12px)',width:'12px',height:'24px'}} onClick={()=>bet('0_3')}/>

            <div className="absolute cursor-pointer hover:bg-purple-400/30 rounded-full z-20" style={{left:`calc(${colW}% - 7px)`,top:'calc(40% - 7px)',width:'14px',height:'14px'}} onClick={()=>bet('0_1_2')}/>
            <div className="absolute cursor-pointer hover:bg-purple-400/30 rounded-full z-20" style={{left:`calc(${colW}% - 7px)`,top:'calc(20% - 7px)',width:'14px',height:'14px'}} onClick={()=>bet('0_2_3')}/>
            <div className="absolute cursor-pointer hover:bg-cyan-400/30 rounded-full z-20" style={{left:`calc(${colW}% - 8px)`,top:'calc(60% - 8px)',width:'16px',height:'16px'}} onClick={()=>bet('0_1_2_3')}/>

            {/* Placed Chips Layer */}
            <div className="absolute inset-0 pointer-events-none">
                {Object.entries(bets).map(([k,v])=>{
                    const p = getChipPosition(k);
                    return <div key={k} className="absolute -translate-x-1/2 -translate-y-1/2 z-40 transition-all duration-300 ease-out" style={{left:p.left,top:p.top}}><CasinoChip value={v} size="board"/></div>;
                })}
            </div>
        </div>
    );
};

export default BettingBoard;

import React, { useMemo } from 'react';
import { WHEEL_NUMBERS, RED_NUMBERS } from '../constants';

const RouletteWheel3D: React.FC<{rotation: number; lastNumber: number | null; spinDuration?: number}> = ({ rotation, lastNumber, spinDuration = 4000 }) => {
    // Exact colors matching the betting board
    const COLOR_RED = '#D92D28';
    const COLOR_BLACK = '#1F2633';
    const COLOR_GREEN = '#0C5C30';

    const segments = useMemo(() => 
        WHEEL_NUMBERS.map((num, i) => {
            let color = COLOR_BLACK;
            if (num === 0) color = COLOR_GREEN;
            else if (RED_NUMBERS.has(num)) color = COLOR_RED;

            return { 
                num, 
                angle: i * (360 / 37), 
                color 
            };
        }), 
    []);

    return (
        <div className="relative flex items-center justify-center" style={{ perspective: '800px' }}>
            {/* Outer wooden frame - thin */}
            <div 
                className="absolute w-[240px] h-[240px] sm:w-[300px] sm:h-[300px] lg:w-[380px] lg:h-[380px] rounded-full shadow-[0_20px_50px_rgba(0,0,0,0.8)]" 
                style={{ transform: 'rotateX(20deg)', background: 'linear-gradient(to bottom, #78350f, #451a03)' }} 
            />
            {/* Inner wooden ring - tighter */}
            <div 
                className="absolute w-[230px] h-[230px] sm:w-[288px] sm:h-[288px] lg:w-[366px] lg:h-[366px] rounded-full border-4 border-[#5d2606]" 
                style={{ transform: 'rotateX(20deg)', background: 'linear-gradient(to bottom, #92400e, #78350f)' }} 
            />
            {/* Chrome rim */}
            <div 
                className="absolute w-[222px] h-[222px] sm:w-[278px] sm:h-[278px] lg:w-[354px] lg:h-[354px] rounded-full shadow-inner" 
                style={{ transform: 'rotateX(20deg)', background: 'linear-gradient(135deg, #e5e7eb 0%, #9ca3af 50%, #4b5563 100%)' }} 
            />
            {/* Ball track */}
            <div 
                className="absolute w-[216px] h-[216px] sm:w-[270px] sm:h-[270px] lg:w-[344px] lg:h-[344px] rounded-full shadow-[inset_0_2px_4px_rgba(0,0,0,0.5)]" 
                style={{ transform: 'rotateX(20deg)', background: 'conic-gradient(from 180deg, #27272a, #18181b)' }} 
            />

            {/* Main Wheel */}
            <div className="relative w-[200px] h-[200px] sm:w-[250px] sm:h-[250px] lg:w-[320px] lg:h-[320px]" style={{ transform: 'rotateX(20deg)' }}>
                <div 
                    className="absolute inset-0 rounded-full overflow-hidden shadow-2xl" 
                    style={{ transform: `rotate(${rotation}deg)`, transition: `transform ${spinDuration}ms cubic-bezier(0.15, 0.6, 0.2, 1)` }}
                >
                    <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-xl">
                        <defs>
                            <linearGradient id="gld" x1="0%" y1="0%" x2="0%" y2="100%">
                                <stop offset="0%" stopColor="#fcd34d" />
                                <stop offset="100%" stopColor="#b45309" />
                            </linearGradient>
                            <radialGradient id="cone" cx="50%" cy="50%" r="50%">
                                <stop offset="0%" stopColor="#b45309" />
                                <stop offset="100%" stopColor="#451a03" />
                            </radialGradient>
                        </defs>

                        {/* Wheel segments */}
                        {segments.map((seg, i) => {
                            // Calculating path for each wedge
                            const a1 = (i * 360 / 37 - 360 / 74 - 90) * Math.PI / 180;
                            const a2 = (i * 360 / 37 + 360 / 74 - 90) * Math.PI / 180;
                            const r1 = 48, r2 = 26;
                            const path = `M ${50 + r1 * Math.cos(a1)} ${50 + r1 * Math.sin(a1)} A ${r1} ${r1} 0 0 1 ${50 + r1 * Math.cos(a2)} ${50 + r1 * Math.sin(a2)} L ${50 + r2 * Math.cos(a2)} ${50 + r2 * Math.sin(a2)} A ${r2} ${r2} 0 0 0 ${50 + r2 * Math.cos(a1)} ${50 + r2 * Math.sin(a1)} Z`;

                            // Text position
                            const ta = i * 360 / 37 - 90;
                            const textRadius = 42;
                            const tx = 50 + textRadius * Math.cos(ta * Math.PI / 180);
                            const ty = 50 + textRadius * Math.sin(ta * Math.PI / 180);

                            return (
                                <g key={seg.num}>
                                    <path d={path} fill={seg.color} stroke="#171717" strokeWidth="0.2" />
                                    {/* Gold separators */}
                                    <line x1={50 + r1 * Math.cos(a1)} y1={50 + r1 * Math.sin(a1)} x2={50 + r2 * Math.cos(a1)} y2={50 + r2 * Math.sin(a1)} stroke="url(#gld)" strokeWidth="0.5" />
                                    <text x={tx} y={ty} fill="white" fontSize="5" fontWeight="900" textAnchor="middle" dominantBaseline="middle" transform={`rotate(${i * 360 / 37}, ${tx}, ${ty})`} style={{textShadow: '0px 1px 1px rgba(0,0,0,0.8)'}}>
                                        {seg.num}
                                    </text>
                                </g>
                            );
                        })}

                        {/* Inner circle with text */}
                        <circle cx="50" cy="50" r="26" fill="#18181b" stroke="url(#gld)" strokeWidth="1" />
                        <text 
                            x="50" 
                            y="50" 
                            fill="#d4af37" 
                            fontSize="6" 
                            fontWeight="700" 
                            textAnchor="middle" 
                            dominantBaseline="middle"
                            style={{ textShadow: '0 1px 2px rgba(0,0,0,0.8)', letterSpacing: '0.5px' }}
                        >
                            Randseed
                        </text>
                    </svg>
                </div>
            </div>

            {/* Pointer Pin */}
            <div className="absolute top-0 left-1/2 z-30 drop-shadow-md" style={{ transform: 'translateX(-50%) rotateX(20deg) translateY(4px)' }}>
                <div className="w-0 h-0 border-l-[6px] border-l-transparent border-r-[6px] border-r-transparent border-t-[14px] border-t-yellow-400 filter drop-shadow" />
            </div>

            {/* Result display overlay */}
            {lastNumber !== null && (
                <div className="absolute inset-0 flex items-center justify-center z-40 pointer-events-none">
                    <div 
                        className={`text-6xl sm:text-7xl font-black animate-bounce ${
                            lastNumber === 0 ? 'text-[#0C5C30]' : RED_NUMBERS.has(lastNumber) ? 'text-[#D92D28]' : 'text-white'
                        }`} 
                        style={{ textShadow: '0 0 40px rgba(0,0,0,0.9), 0 0 10px currentColor' }}
                    >
                        {lastNumber}
                    </div>
                </div>
            )}
        </div>
    );
};

export default RouletteWheel3D;

import React from 'react';
