//欧式轮盘下注类型定义
type RouletteBetType = variant {
    // --- 内围注 (Inside Bets) ---

    // 直注 / 单号 (Straight Up)
    // 赔率: 35:1
    // 说明: 下注在 0-36 中任意一个特定号码上
    Straight : nat8; 

    // 分注 / 双号 (Split)
    // 赔率: 17:1
    // 说明: 下注在两个相邻号码的分割线上 (传入包含2个号码的数组)
    Split : vec nat8; 

    // 街注 / 三号 (Street)
    // 赔率: 11:1
    // 说明: 下注在横排三个号码的边缘线上 (传入包含3个号码的数组)
    Street : vec nat8; 

    // 角注 / 四号 (Corner)
    // 赔率: 8:1
    // 说明: 下注在四个号码交接的十字路口 (传入包含4个号码的数组)
    Corner : vec nat8; 

    // 线注 / 六号 (Line)
    // 赔率: 5:1
    // 说明: 下注在两个相邻横排的边缘交点 (传入包含6个号码的数组)
    Line : vec nat8; 

    // 三数注 (Trio) - 特殊内围注
    // 赔率: 11:1
    // 说明: 涉及 0 的交点 (如 0-1-2 或 0-2-3) (传入包含3个号码的数组)
    Trio : vec nat8; 

    // 篮注 (Basket / First Four) - 特殊内围注
    // 赔率: 8:1
    // 说明: 下注 0-1-2-3 (传入包含这4个号码的数组)
    Basket : vec nat8; 

    // --- 外围注 (Outside Bets) ---

    // 列注 (Column)
    // 赔率: 2:1
    // 说明: 覆盖一整竖列 (12个号码)
    Column1; // 第1列 (1, 4, 7 ... 34)
    Column2; // 第2列 (2, 5, 8 ... 35)
    Column3; // 第3列 (3, 6, 9 ... 36)

    // 打注 (Dozen)
    // 赔率: 2:1
    // 说明: 覆盖 12 个连续号码
    Dozen1; // 1st 12 (1-12)
    Dozen2; // 2nd 12 (13-24)
    Dozen3; // 3rd 12 (25-36)

    // 红 / 黑 (Red / Black)
    // 赔率: 1:1
    // 说明: 18个号码
    Red;
    Black;

    // 单 / 双 (Odd / Even)
    // 赔率: 1:1
    // 说明: 18个号码
    Odd;
    Even;

    // 大 / 小 (High / Low)
    // 赔率: 1:1
    // 说明: 18个号码
    Low;  // 1-18
    High; // 19-36
};

