export type GamePhase = 'betting' | 'locked' | 'spinning' | 'result';

export interface PlayerBet {
  username: string;
  number: string;
  amount: number;
}

export interface BetAction {
  id: string;
  amount: number;
}

export interface ChipProps {
  value: number;
  className?: string;
  size?: "xs" | "sm" | "md" | "lg" | "board" | "selector";
}

export interface GameRecord {
  id: number;
  result: number;
  betAmount: number;
  winAmount: number;
  timestamp: Date;
}

// Backend Data Structures (Motoko/Candid Compatibility)
export type BackendBetType = 
    | { Straight: number }
    | { Split: number[] }
    | { Street: number[] }
    | { Corner: number[] }
    | { Line: number[] }
    | { Trio: number[] }
    | { Basket: number[] }
    | { Column1: null }
    | { Column2: null }
    | { Column3: null }
    | { Dozen1: null }
    | { Dozen2: null }
    | { Dozen3: null }
    | { Red: null }
    | { Black: null }
    | { Odd: null }
    | { Even: null }
    | { Low: null }
    | { High: null };

export interface BackendBetEntry {
    betType: BackendBetType;
    amount: number;
}

import { RED_NUMBERS } from './constants';
import { BackendBetEntry, BackendBetType } from './types';

export const getNumberColor = (num: number): string => {
  if (num === 0) return 'green';
  if (RED_NUMBERS.has(num)) return 'red';
  return 'black';
};

export const getChipColor = (value: number) => {
  if (value === 1) return 'bg-gray-300 text-gray-900 ring-gray-400'; 
  if (value === 2) return 'bg-blue-600 text-white ring-blue-400';
  if (value === 5) return 'bg-white text-gray-900 ring-yellow-500';
  if (value === 10) return 'bg-red-600 text-white ring-red-400';
  if (value === 20) return 'bg-emerald-600 text-white ring-emerald-400';
  return 'bg-gray-500';
};

export const getBetNumbers = (betId: string): number[] => {
  if (betId.includes('_')) {
      return betId.split('_').map(Number);
  }
  const n = parseInt(betId);
  if (!isNaN(n)) return [n];
  return [];
};

export const calculateWinnings = (result: number, bets: Record<string, number>): number => {
  let winnings = 0;
  Object.entries(bets).forEach(([betId, amount]) => {
      let isWin = false, multiplier = 0;

      if (betId.match(/^[\d_]+$/)) {
          const numbers = getBetNumbers(betId);
          if (numbers.includes(result)) { 
              isWin = true; 
              multiplier = 36 / numbers.length; 
          }
      } else {
          switch(betId) {
              case '1st12': isWin = result >= 1 && result <= 12; multiplier = 3; break;
              case '2nd12': isWin = result >= 13 && result <= 24; multiplier = 3; break;
              case '3rd12': isWin = result >= 25 && result <= 36; multiplier = 3; break;
              case '1-18': isWin = result >= 1 && result <= 18; multiplier = 2; break;
              case '19-36': isWin = result >= 19 && result <= 36; multiplier = 2; break;
              case 'EVEN': isWin = result !== 0 && result % 2 === 0; multiplier = 2; break;
              case 'ODD': isWin = result !== 0 && result % 2 !== 0; multiplier = 2; break;
              case 'RED': isWin = RED_NUMBERS.has(result); multiplier = 2; break;
              case 'BLACK': isWin = !RED_NUMBERS.has(result) && result !== 0; multiplier = 2; break;
              case 'row1': isWin = result !== 0 && result % 3 === 1; multiplier = 3; break;
              case 'row2': isWin = result !== 0 && result % 3 === 2; multiplier = 3; break;
              case 'row3': isWin = result !== 0 && result % 3 === 0; multiplier = 3; break;
          }
      }
      if (isWin) winnings += amount * multiplier;
  });
  return winnings;
};

export const getHotCold = (history: number[]) => {
  const freq: Record<number, number> = {};
  for (let i = 0; i <= 36; i++) freq[i] = 0;
  history.slice(0, 50).forEach(n => freq[n]++);
  const sorted = Object.entries(freq).sort((a, b) => b[1] - a[1]);
  return { 
      hot: sorted.slice(0, 3).map(([n]) => +n), 
      cold: sorted.slice(-3).reverse().map(([n]) => +n) 
  };
};

// Converts local betting state to backend data structure
export const prepareBetsForBackend = (bets: Record<string, number>): BackendBetEntry[] => {
    return Object.entries(bets).map(([betId, amount]) => {
      let betType: BackendBetType;

      // Mapped Strings
      if (betId === 'row1') betType = { Column1: null };
      else if (betId === 'row2') betType = { Column2: null };
      else if (betId === 'row3') betType = { Column3: null };
      else if (betId === '1st12') betType = { Dozen1: null };
      else if (betId === '2nd12') betType = { Dozen2: null };
      else if (betId === '3rd12') betType = { Dozen3: null };
      else if (betId === 'RED') betType = { Red: null };
      else if (betId === 'BLACK') betType = { Black: null };
      else if (betId === 'EVEN') betType = { Even: null };
      else if (betId === 'ODD') betType = { Odd: null };
      else if (betId === '1-18') betType = { Low: null };
      else if (betId === '19-36') betType = { High: null };
      else {
        // Number Sets
        const nums = getBetNumbers(betId);
        const len = nums.length;

        if (len === 1) {
          betType = { Straight: nums[0] };
        } else if (len === 2) {
          betType = { Split: nums };
        } else if (len === 3) {
          // 0-1-2 or 0-2-3 -> Trio
          if (nums.includes(0)) {
             betType = { Trio: nums };
          } else {
             betType = { Street: nums };
          }
        } else if (len === 4) {
          // 0-1-2-3 -> Basket
          if (nums.includes(0)) {
              betType = { Basket: nums };
          } else {
              betType = { Corner: nums };
          }
        } else if (len === 6) {
          betType = { Line: nums };
        } else {
           // Fallback
           console.warn("Unknown bet pattern:", betId, nums);
           betType = { Straight: 0 }; 
        }
      }

      return { betType, amount };
    });
  };

import React, { useState, useEffect, useCallback } from 'react';
import { NavBar, LiveFeed, BalanceBar, HistoryPanel, ControlPanel } from './components/UI';
import BettingBoard from './components/BettingBoard';
import RouletteWheel3D from './components/RouletteWheel3D';
import { GamePhase, PlayerBet, BetAction, GameRecord } from './types';
import { WHEEL_NUMBERS, CHIP_VALUES, BOT_NAMES } from './constants';
import { calculateWinnings, prepareBetsForBackend } from './utils';
import { soundManager } from './services/SoundManager';

const App = () => {
    // View State
    const [viewMode, setViewMode] = useState<'full' | 'mobile'>('full');

    // Game State
    const [balance, setBalance] = useState(1000);
    const [bets, setBets] = useState<Record<string, number>>({});
    const [betStack, setBetStack] = useState<BetAction[]>([]);
    const [phase, setPhase] = useState<GamePhase>('betting');
    const [lastNum, setLastNum] = useState<number | null>(null);
    const [rotation, setRotation] = useState(0);
    const [history, setHistory] = useState<number[]>([]);

    // Auto Spin State
    const BETTING_TIME = 15;
    const [timeLeft, setTimeLeft] = useState(BETTING_TIME);

    // UI State
    const [chip, setChip] = useState(5);
    const [feed, setFeed] = useState<PlayerBet[]>([]);
    const [muted, setMuted] = useState(false);
    const [showRec, setShowRec] = useState(false);
    const [records, setRecords] = useState<GameRecord[]>([]);

    const betTotal = betStack.reduce((s, b) => s + b.amount, 0);
    const SPIN_DURATION = 10000;

    // Simulated Multiplayer Feed
    useEffect(() => {
        const i = setInterval(() => {
            if (Math.random() > 0.4) {
                setFeed(f => [{
                    username: BOT_NAMES[Math.floor(Math.random() * BOT_NAMES.length)],
                    number: String(Math.floor(Math.random() * 37)),
                    amount: CHIP_VALUES[Math.floor(Math.random() * CHIP_VALUES.length)]
                }, ...f].slice(0, 8));
            }
        }, 2500);
        return () => clearInterval(i);
    }, []);

    // Sync Mute State
    useEffect(() => { soundManager.setMuted(muted); }, [muted]);

    const placeBet = (id: string) => {
        if (phase !== 'betting' || balance < chip) return;
        soundManager.playChipPlace();
        setBalance(b => b - chip);
        setBets(b => ({ ...b, [id]: (b[id] || 0) + chip }));
        setBetStack(s => [...s, { id, amount: chip }]);
    };

    const undo = () => {
        if (phase !== 'betting' || !betStack.length) return;
        const last = betStack[betStack.length - 1];
        setBalance(b => b + last.amount);
        setBets(b => {
            const n = { ...b };
            n[last.id] -= last.amount;
            if (n[last.id] <= 0) delete n[last.id];
            return n;
        });
        setBetStack(s => s.slice(0, -1));
    };

    const clear = () => {
        if (phase !== 'betting') return;
        setBalance(b => b + betTotal);
        setBets({});
        setBetStack([]);
    };

    // Memoized spin function to be used in effects
    const spin = useCallback(() => {
        // Allow spin even with 0 bets (Auto spin requirement)
        setPhase('spinning');
        soundManager.playSpinSound(SPIN_DURATION);

        const resultIndex = Math.floor(Math.random() * 37);
        const winningNumber = WHEEL_NUMBERS[resultIndex];

        // Calculate Rotation
        const anglePerItem = 360 / 37;
        const targetAngle = resultIndex * anglePerItem;

        // We use a functional update for rotation to ensure we have the latest value
        setRotation(prevRotation => {
            const currentMod = prevRotation % 360;
            const targetMod = (360 - targetAngle) % 360; 

            let diff = targetMod - currentMod;
            if (diff < 0) diff += 360; 

            const extraSpins = 12 * 360;
            return prevRotation + extraSpins + diff;
        });

        // Resolution
        setTimeout(() => {
            setLastNum(winningNumber);
            setPhase('result');
            setHistory(prev => [winningNumber, ...prev]);
        }, SPIN_DURATION);
    }, []); 

    // Handle Winnings and Reset (Post-Spin Logic)
    useEffect(() => {
        if (phase === 'result' && lastNum !== null) {

            // GENERATE AND LOG BACKEND PAYLOAD HERE
            const backendPayload = prepareBetsForBackend(bets);
            console.log("🚀 PAYLOAD TO BACKEND:", JSON.stringify(backendPayload, null, 2));

            const winAmount = calculateWinnings(lastNum, bets);

            if (winAmount > 0) {
                setBalance(b => b + winAmount);
                soundManager.playWin();
            } else {
                soundManager.playLose();
            }

            // Record Game
            setRecords(prev => [{
                id: Date.now(),
                result: lastNum,
                betAmount: betTotal,
                winAmount: winAmount,
                timestamp: new Date()
            }, ...prev]);

            // Auto Reset after result display
            const timer = setTimeout(() => {
                setPhase('betting');
                setLastNum(null);
                setBets({});
                setBetStack([]);
                setTimeLeft(BETTING_TIME); // Reset Timer
            }, 3500);
            return () => clearTimeout(timer);
        }
    }, [phase, lastNum]); // Only run when phase changes to result

    // Auto-Spin Timer Logic
    useEffect(() => {
        let interval: ReturnType<typeof setInterval>;
        if (phase === 'betting') {
            if (timeLeft > 0) {
                interval = setInterval(() => {
                    setTimeLeft(t => Math.max(0, t - 1));
                }, 1000);
            } else {
                // Time is up, trigger spin
                spin();
            }
        }
        return () => clearInterval(interval);
    }, [phase, timeLeft, spin]);

    // Style logic for the main container based on view mode
    const containerClass = viewMode === 'mobile' 
        ? 'relative w-[375px] h-[750px] max-h-[95vh] mx-auto my-auto mt-4 sm:mt-8 border-[8px] border-slate-800 rounded-[3rem] shadow-2xl overflow-hidden bg-[#0f172a] flex flex-col ring-4 ring-black/20'
        : 'fixed inset-0 bg-[#0f172a] text-white flex flex-col overflow-hidden';

    const wrapperClass = viewMode === 'mobile'
        ? 'fixed inset-0 bg-gradient-to-br from-slate-900 to-black flex items-center justify-center overflow-auto p-4'
        : '';

    const isMobile = viewMode === 'mobile';

    return (
        <div className={wrapperClass}>
            <div className={containerClass}>
                <NavBar 
                    onExit={() => window.location.reload()} 
                    isMuted={muted} 
                    setIsMuted={setMuted}
                    viewMode={viewMode}
                    onToggleView={() => setViewMode(v => v === 'full' ? 'mobile' : 'full')}
                />

                <LiveFeed feed={feed} />

                <BalanceBar 
                    balance={balance} 
                    betTotal={betTotal} 
                    records={records}
                    showRec={showRec}
                    setShowRec={setShowRec}
                />

                {/* Main Content Area */}
                <main className={`flex-1 min-h-0 ${isMobile ? 'flex flex-col px-2 pt-2 pb-3 overflow-hidden' : 'flex items-center justify-center p-6 overflow-hidden'}`}>
                    <div className={`w-full mx-auto transition-all duration-500 h-full ${isMobile ? 'flex flex-col justify-between' : 'flex flex-row items-center justify-center gap-12 max-w-7xl'}`}>

                        {/* Wheel Section */}
                        <div className={`flex flex-col items-center justify-center ${isMobile ? 'shrink-0 scale-[0.6] -my-10 h-[200px]' : 'flex-1 max-w-[450px]'}`}>
                             <div className={!isMobile ? 'scale-110 mb-8' : ''}>
                                <RouletteWheel3D rotation={rotation} lastNumber={lastNum} spinDuration={SPIN_DURATION} />
                             </div>

                             {!isMobile && (
                                 <div className="w-full mt-8">
                                     <HistoryPanel history={history} />
                                 </div>
                             )}
                        </div>

                        {/* Betting Board Section + Controls */}
                        <div className={`flex flex-col items-center justify-center gap-2 ${isMobile ? 'w-full shrink-0 z-10 flex-1 min-h-0' : 'flex-[1.5] w-full max-w-[900px]'}`}>
                             {/* Mobile History Panel moved here */}
                             {isMobile && (
                                <div className="w-full mb-1">
                                    <HistoryPanel history={history} />
                                </div>
                             )}

                             <BettingBoard bets={bets} onBet={placeBet} phase={phase} />

                             {/* Control Panel with Auto-Spin Timer */}
                             <div className="w-full shrink-0 px-1 sm:px-0">
                                <ControlPanel 
                                    chip={chip} 
                                    setChip={setChip} 
                                    undo={undo} 
                                    clear={clear} 
                                    phase={phase}
                                    hasBets={betTotal > 0}
                                    timeLeft={timeLeft}
                                    maxTime={BETTING_TIME}
                                />
                             </div>
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
};

