                <main className={`flex-1 min-h-0 ${isMobile ? 'flex flex-col px-2 pt-2 pb-3 overflow-hidden' : 'flex items-center justify-center p-6 overflow-hidden'}`}>
                    <div className={`w-full mx-auto transition-all duration-500 h-full ${isMobile ? 'flex flex-col justify-between' : 'flex flex-row items-center justify-center gap-12 max-w-7xl'}`}>

                        {/* Wheel Section */}
                        <div className={`flex flex-col items-center justify-center ${isMobile ? 'shrink-0 scale-[0.6] -my-10 h-[200px]' : 'flex-1 max-w-[450px]'}`}>
                             <div className={!isMobile ? 'scale-110 mb-8' : ''}>
                                <RouletteWheel3D rotation={rotation} lastNumber={lastNum} spinDuration={SPIN_DURATION} />
                             </div>

                             {!isMobile && (
                                 <div className="w-full mt-8">
                                     <HistoryPanel history={history} />
                                 </div>
                             )}
                        </div>

                        {/* Betting Board Section + Controls */}
                        <div className={`flex flex-col items-center justify-center gap-2 ${isMobile ? 'w-full shrink-0 z-10 flex-1 min-h-0' : 'flex-[1.5] w-full max-w-[900px]'}`}>
                             {/* Mobile History Panel moved here */}
                             {isMobile && (
                                <div className="w-full mb-1">
                                    <HistoryPanel history={history} />
                                </div>
                             )}

                             <BettingBoard bets={bets} onBet={placeBet} phase={phase} />

                             {/* Control Panel with Auto-Spin Timer */}
                             <div className="w-full shrink-0 px-1 sm:px-0">
                                <ControlPanel 
                                    chip={chip} 
                                    setChip={setChip} 
                                    undo={undo} 
                                    clear={clear} 
                                    phase={phase}
                                    hasBets={betTotal > 0}
                                    timeLeft={timeLeft}
                                    maxTime={BETTING_TIME}
                                />
                             </div>
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
};

