        selector: "w-[15px] h-[15px] text-[6px] ring-1 sm:w-11 sm:h-11 sm:text-[11px] md:w-12 md:h-12 md:text-xs"
    };

    const currentSizeClass = sizeClasses[size] || sizeClasses.md;
