                    <div className="flex items-center gap-1">
                        <span className={`font-mono font-bold text-lg sm:text-xl filter drop-shadow-sm ${gainColor}`}>
                            {latestNet > 0 ? '+' : ''}{latestNet === 0 ? '$0' : `$${latestNet}`}
