                                    </div>
                                ))
                            )}
                            <div className="w-1 shrink-0" />
                        </div>
                    </div>

                    {/* Divider */}
                    <div className="w-px bg-white/10 self-stretch shrink-0" />

                    {/* Right - Hot/Cold stacked - CLICKABLE */}
                    <button 
                        onClick={() => setShowStats(true)}
                        className="relative flex flex-col gap-1 shrink-0 justify-center min-w-[fit-content] pr-1 pl-2 hover:bg-white/5 rounded-r-lg transition-colors group"
                        title="View Full Statistics"
                    >
                        <div className="absolute top-0.5 right-0.5 opacity-50 group-hover:opacity-100 transition-opacity">
                             <ChevronsRight size={10} className="text-gray-400" />
                        </div>

                        {/* Hot */}
                        <div className="flex items-center gap-3">
                            <Flame size={12} className="text-orange-500 shrink-0 group-hover:scale-110 transition-transform" />
                            <div className="flex gap-1.5 font-mono">
                                {stats.hot.map((n, i) => (
                                    <span key={`h${i}`} className={`text-xs font-black ${n === 0 ? 'text-emerald-400' : RED_NUMBERS.has(n) ? 'text-red-400' : 'text-slate-200'}`}>{n}</span>
                                ))}
                            </div>
                        </div>
                        {/* Cold */}
                        <div className="flex items-center gap-3">
                            <Snowflake size={12} className="text-blue-500 shrink-0 group-hover:scale-110 transition-transform" />
                            <div className="flex gap-1.5 font-mono">
                                {stats.cold.map((n, i) => (
                                    <span key={`c${i}`} className={`text-xs font-black ${n === 0 ? 'text-emerald-400' : RED_NUMBERS.has(n) ? 'text-red-400' : 'text-slate-200'}`}>{n}</span>
                                ))}
                            </div>
                        </div>
                    </button>
                </div>
            </div>

            {/* Stats Modal */}
            {showStats && <StatsOverlay stats={stats} onClose={() => setShowStats(false)} />}
        </>
    );
};

