import React, { useState, useEffect, useCallback, useRef } from 'react';
import { NavBar, LiveFeed, BalanceBar, HistoryPanel, ControlPanel } from './components/UI';
import BettingBoard from './components/BettingBoard';
import RouletteWheel3D from './components/RouletteWheel3D';
import { GamePhase, PlayerBet, BetAction, GameRecord, GameStats } from './types';
import { WHEEL_NUMBERS, CHIP_VALUES, BOT_NAMES } from './constants';
import { calculateWinnings, prepareBetsForBackend } from './utils';
import { soundManager } from './services/SoundManager';
import { mockBackend } from './services/MockBackend';

const App = () => {
    // Game State
    const [balance, setBalance] = useState(1000);
    const [bets, setBets] = useState<Record<string, number>>({});
    const [betStack, setBetStack] = useState<BetAction[]>([]);
    const [phase, setPhase] = useState<GamePhase>('betting');
    const [lastNum, setLastNum] = useState<number | null>(null);
    const [rotation, setRotation] = useState(0);

    // Backend Data
    const [history, setHistory] = useState<number[]>([]);
    const [stats, setStats] = useState<GameStats>({ hot: [], cold: [], redPct: 0, blackPct: 0, evenPct: 0, oddPct: 0, lowPct: 0, highPct: 0 });
    const nextRoundData = useRef<{ history: number[], stats: GameStats } | null>(null);

    // Auto Spin State
    const BETTING_TIME = 15;
    const [timeLeft, setTimeLeft] = useState(BETTING_TIME);

    // UI State
    const [chip, setChip] = useState(5);
    const [feed, setFeed] = useState<PlayerBet[]>([]);
    const [muted, setMuted] = useState(false);
    const [showRec, setShowRec] = useState(false);
    const [records, setRecords] = useState<GameRecord[]>([]);

    const betTotal = betStack.reduce((s, b) => s + b.amount, 0);
    const SPIN_DURATION = 10000;

    // Load Initial Data
    useEffect(() => {
        mockBackend.getInitialData().then(data => {
            setHistory(data.history);
            setStats(data.stats);
        });
    }, []);

    // Simulated Multiplayer Feed
    useEffect(() => {
        const i = setInterval(() => {
            if (Math.random() > 0.4) {
                setFeed(f => [{
                    username: BOT_NAMES[Math.floor(Math.random() * BOT_NAMES.length)],
                    number: String(Math.floor(Math.random() * 37)),
                    amount: CHIP_VALUES[Math.floor(Math.random() * CHIP_VALUES.length)]
                }, ...f].slice(0, 8));
            }
        }, 2500);
        return () => clearInterval(i);
    }, []);

    // Sync Mute State
    useEffect(() => { soundManager.setMuted(muted); }, [muted]);

    const placeBet = (id: string) => {
        if (phase !== 'betting' || balance < chip) return;
        soundManager.playChipPlace();
        setBalance(b => b - chip);
        setBets(b => ({ ...b, [id]: (b[id] || 0) + chip }));
        setBetStack(s => [...s, { id, amount: chip }]);
    };

    const undo = () => {
        if (phase !== 'betting' || !betStack.length) return;
        const last = betStack[betStack.length - 1];
        setBalance(b => b + last.amount);
        setBets(b => {
            const n = { ...b };
            n[last.id] -= last.amount;
            if (n[last.id] <= 0) delete n[last.id];
            return n;
        });
        setBetStack(s => s.slice(0, -1));
    };

    const clear = () => {
        if (phase !== 'betting') return;
        setBalance(b => b + betTotal);
        setBets({});
        setBetStack([]);
    };

    // Trigger Spin Animation
    const spin = useCallback((winningNumber: number) => {
        setPhase('spinning');
        soundManager.playSpinSound(SPIN_DURATION);

        const resultIndex = WHEEL_NUMBERS.indexOf(winningNumber);
        const anglePerItem = 360 / 37;
        const targetAngle = resultIndex * anglePerItem;

        setRotation(prevRotation => {
            const currentMod = prevRotation % 360;
            const targetMod = (360 - targetAngle) % 360; 
            let diff = targetMod - currentMod;
            if (diff < 0) diff += 360; 
            return prevRotation + (12 * 360) + diff;
        });

        setTimeout(() => {
            setLastNum(winningNumber);
            setPhase('result');
        }, SPIN_DURATION);
    }, []); 

    // Handle Game Flow
    const handleGameSequence = useCallback(async () => {
        if (phase !== 'betting') return;

        setPhase('locked');

        const backendPayload = prepareBetsForBackend(bets);

        try {
            // Call Backend
            const { result, history: newHistory, stats: newStats } = await mockBackend.placeBets(backendPayload);

            // Store new data to apply after spin
            nextRoundData.current = { history: newHistory, stats: newStats };

            // Start Animation
            spin(result);

        } catch (error) {
            console.error("Backend Error:", error);
            setPhase('betting'); 
        }

    }, [phase, bets, spin]);

    // Post-Spin Result Logic
    useEffect(() => {
        if (phase === 'result' && lastNum !== null) {
            // Calculate Winnings
            const winAmount = calculateWinnings(lastNum, bets);

            if (winAmount > 0) {
                setBalance(b => b + winAmount);
                soundManager.playWin();
            } else {
                soundManager.playLose();
            }

            // Update History and Stats from Backend response
            if (nextRoundData.current) {
                setHistory(nextRoundData.current.history);
                setStats(nextRoundData.current.stats);
                nextRoundData.current = null;
            }

            // Record Game for User Log
            setRecords(prev => [{
                id: Date.now(),
                result: lastNum,
                betAmount: betTotal,
                winAmount: winAmount,
                timestamp: new Date()
            }, ...prev]);

            // Auto Reset
            const timer = setTimeout(() => {
                setPhase('betting');
                setLastNum(null);
                setBets({});
                setBetStack([]);
                setTimeLeft(BETTING_TIME);
            }, 3500);
            return () => clearTimeout(timer);
        }
    }, [phase, lastNum]);

    // Timer Tick
    useEffect(() => {
        if (phase === 'betting' && timeLeft > 0) {
            const timer = setTimeout(() => setTimeLeft(t => Math.max(0, t - 1)), 1000);
            return () => clearTimeout(timer);
        }
    }, [phase, timeLeft]);

    // Trigger Game Sequence on Time Up
    useEffect(() => {
        if (phase === 'betting' && timeLeft === 0) {
            handleGameSequence();
        }
    }, [phase, timeLeft, handleGameSequence]);

    return (
        <div className="fixed inset-0 bg-[#0f172a] text-white flex flex-col overflow-hidden font-sans select-none">
            <NavBar 
                onExit={() => window.location.reload()} 
                isMuted={muted} 
                setIsMuted={setMuted}
            />

            <LiveFeed feed={feed} />

            <BalanceBar 
                balance={balance} 
                betTotal={betTotal} 
                records={records}
                showRec={showRec}
                setShowRec={setShowRec}
            />

            {/* Content Container - Items stretch ensures columns equal height on desktop */}
            <main className="flex-1 min-h-0 w-full max-w-[1800px] mx-auto p-2 sm:p-4 lg:p-8 flex flex-col lg:flex-row items-stretch justify-center gap-2 lg:gap-16 overflow-hidden">

                {/* Left Section (Wheel & Stats) 
                    Mobile: flex-1 to take up all empty space (more wheel room).
                    Desktop: Wider width (500px) so History panel isn't too small/narrow.
                */}
                <div className="flex-1 lg:flex-none lg:shrink-0 flex flex-col items-center justify-between z-0 relative lg:w-[500px]">
                     {/* Wheel Container - Centered in available space top */}
                     <div className="flex-1 flex items-center justify-center w-full">
                         {/* Scale down wheel on mobile to fit nicely, up on desktop */}
                         <div className="transform scale-[0.65] sm:scale-75 md:scale-90 lg:scale-100 xl:scale-110 transition-transform duration-500 origin-center -my-6 sm:my-0">
                            <RouletteWheel3D rotation={rotation} lastNumber={lastNum} spinDuration={SPIN_DURATION} />
                         </div>
                     </div>

                     {/* Desktop History - Bottom Aligned with Controls via justify-between on parent */}
                     <div className="hidden lg:block w-full">
                         <HistoryPanel history={history} stats={stats} />
                     </div>
                </div>

                {/* Right Section (Board & Controls)
                    Mobile: shrink-0 to fit content only (compact bottom).
                    Desktop: flex-1 to take remaining width, but max-width constrained to 700px (smaller board).
                */}
                <div className="shrink-0 lg:flex-1 lg:shrink-1 w-full max-w-[700px] flex flex-col gap-1.5 sm:gap-4 lg:h-auto justify-end lg:justify-center z-10 pb-1 lg:pb-0">

                    {/* Mobile History - Rendered here to sit right on top of board */}
                    <div className="lg:hidden w-full">
                        <HistoryPanel history={history} stats={stats} />
                    </div>

                    {/* Betting Board - No extra flex-1 on mobile to keep it compact */}
                    <div className="w-full flex items-center justify-center min-h-0">
                        <BettingBoard bets={bets} onBet={placeBet} phase={phase} />
                    </div>

                    <ControlPanel 
                        chip={chip} 
                        setChip={setChip} 
                        undo={undo} 
                        clear={clear} 
                        phase={phase}
                        hasBets={betTotal > 0}
                        timeLeft={timeLeft}
                        maxTime={BETTING_TIME}
                    />
                </div>

            </main>
        </div>
    );
};

export default App;

