// Backend Data Structures (Motoko/Candid Compatibility)
export type BackendBetType = 
    | { Straight: number }
    | { Split: number[] }
    | { Street: number[] }
    | { Corner: number[] }
    | { Line: number[] }
    | { Trio: number[] }
    | { Basket: number[] }
    | { Column1: null }
    | { Column2: null }
    | { Column3: null }
    | { Dozen1: null }
    | { Dozen2: null }
    | { Dozen3: null }
    | { Red: null }
    | { Black: null }
    | { Odd: null }
