export const ControlPanel: React.FC<{
    chip: number;
    setChip: (v: number) => void;
    undo: () => void;
    clear: () => void;
    phase: GamePhase;
    hasBets: boolean;
    timeLeft: number;
    maxTime: number;
}> = ({ chip, setChip, undo, clear, phase, hasBets, timeLeft, maxTime }) => {

    const progress = (timeLeft / maxTime) * 100;

    return (
        <div className="w-full max-w-3xl mx-auto flex flex-col gap-2 relative z-20">
            {/* Status Window - Centered above */}
            <div className="self-center flex items-center gap-4 bg-slate-900/90 border border-white/10 px-6 py-2 rounded-full shadow-xl backdrop-blur-md min-w-[200px] justify-center">
                 <div className={`text-sm font-black uppercase tracking-widest ${phase === 'betting' ? 'text-yellow-400' : 'text-slate-400'}`}>
                    {phase === 'betting' ? 'Place Your Bets' : phase === 'locked' ? 'No More Bets' : phase === 'spinning' ? 'Spinning...' : 'Winning Number'}
                 </div>
                 {phase === 'betting' && (
                     <div className="flex items-center gap-1.5 text-white font-mono font-bold bg-white/10 px-2 py-0.5 rounded">
                        <Clock size={12} className="text-yellow-400"/>
                        <span>{timeLeft}s</span>
                     </div>
                 )}
            </div>

            {/* Main Control Strip */}
            <div className="bg-[#1a1a2e] rounded-xl border border-white/10 shadow-2xl overflow-hidden flex flex-col">

                {/* Time Bar - Yellow Only */}
                <div className="h-1.5 w-full bg-slate-800">
                     <div 
                        className="h-full bg-yellow-400 transition-all duration-1000 ease-linear"
                        style={{ width: `${phase === 'betting' ? progress : 0}%` }}
                    />
                </div>

                {/* Buttons and Chips Row */}
                <div className="flex items-center justify-between p-2 sm:p-3 lg:p-4 gap-2 sm:gap-4">

                    {/* Clear (Left) */}
                    <button 
                        onClick={clear}
                        disabled={!hasBets || phase !== 'betting'}
                        className="w-10 h-10 sm:w-14 sm:h-14 flex items-center justify-center rounded-xl bg-slate-800/50 hover:bg-red-900/20 border border-white/5 hover:border-red-500/50 text-slate-400 hover:text-red-400 transition-all active:scale-95 disabled:opacity-30 disabled:pointer-events-none"
                        title="Clear Bets"
                    >
                        <Trash2 size={20} />
                    </button>

                    {/* Chips (Center) */}
                    <div className="flex-1 flex justify-center items-center gap-2 sm:gap-4 lg:gap-6 overflow-x-auto scrollbar-hide py-2">
                        {CHIP_VALUES.map(v => (
                            <button
                                key={v}
                                onClick={() => setChip(v)}
                                className={`
                                    relative transition-all duration-200 shrink-0
                                    ${chip === v ? '-translate-y-1.5 scale-110' : 'hover:-translate-y-1 hover:scale-105 opacity-80 hover:opacity-100'}
                                `}
                            >
                                <CasinoChip 
                                    value={v} 
                                    size="selector"
                                    className={chip === v ? "ring-2 ring-yellow-400 shadow-[0_0_15px_rgba(250,204,21,0.5)]" : ""} 
                                />
                            </button>
                        ))}
                    </div>

                    {/* Undo (Right) */}
                    <button 
                        onClick={undo}
                        disabled={!hasBets || phase !== 'betting'}
                        className="w-10 h-10 sm:w-14 sm:h-14 flex items-center justify-center rounded-xl bg-slate-800/50 hover:bg-blue-900/20 border border-white/5 hover:border-blue-500/50 text-slate-400 hover:text-blue-400 transition-all active:scale-95 disabled:opacity-30 disabled:pointer-events-none"
                        title="Undo Last Bet"
                    >
                        <Undo2 size={20} />
                    </button>
                </div>
            </div>
        </div>
    );
};

import React, { useMemo, useState, useEffect } from 'react';
