                    ) : (
                        <div className="divide-y divide-white/5">
                            {records.map(r => {
                                const net = r.winAmount - r.betAmount;
                                return (
                                    <div key={r.id} className="p-2 flex justify-between text-xs hover:bg-white/5">
                                        <div className="flex items-center gap-2">
                                            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold ${
                                                r.result === 0 ? 'bg-emerald-600' : RED_NUMBERS.has(r.result) ? 'bg-[#D92D28]' : 'bg-zinc-800'
                                            }`}>{r.result}</div>
                                            <span className="text-gray-400">{r.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit', second:'2-digit'})}</span>
                                        </div>
                                        <span className={net > 0 ? 'text-emerald-400 font-semibold' : net < 0 ? 'text-red-400' : 'text-gray-500'}>
                                            {net > 0 ? `+$${net}` : net < 0 ? `-$${Math.abs(net)}` : '$0'}
                                        </span>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

// ==========================================
// STATS OVERLAY
// ==========================================
const StatsOverlay: React.FC<{ stats: GameStats, onClose: () => void }> = ({ stats, onClose }) => {
    // Portal to body to escape any stacking contexts
    return createPortal(
        <div 
            className="fixed inset-0 z-[99999] bg-black/60 backdrop-blur-sm flex justify-center items-center p-4"
            onClick={onClose}
        >
            <div 
                className="w-full max-w-sm bg-[#1a1a2e] rounded-2xl border border-white/10 shadow-2xl p-4 sm:p-6 overflow-y-auto animate-fade-in"
                onClick={e => e.stopPropagation()}
            >
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-lg font-bold text-white flex items-center gap-2">
                        <BarChart2 size={18} className="text-yellow-400"/>
                        Last 50 Spins
                    </h2>
                    <button onClick={onClose} className="p-1 hover:bg-white/10 rounded-full transition-colors">
                        <X size={20} className="text-gray-400" />
                    </button>
                </div>

                <div className="space-y-6">
                    {/* Hot Numbers */}
                    <div>
                        <div className="flex items-center gap-2 mb-2">
                            <Flame size={14} className="text-orange-500" />
                            <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Hot Numbers</span>
                        </div>
                        <div className="flex gap-3">
                            {stats.hot.map((n, i) => (
                                <div key={i} className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm shadow-lg ${
                                    n === 0 ? 'bg-emerald-600' : RED_NUMBERS.has(n) ? 'bg-[#D92D28]' : 'bg-gray-900 border border-gray-600'
                                }`}>
                                    {n}
                                </div>
