                        </div>
                    </div>

                    {/* Cold Numbers */}
                    <div>
                        <div className="flex items-center gap-2 mb-2">
                            <Snowflake size={14} className="text-blue-500" />
                            <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Cold Numbers</span>
                        </div>
                        <div className="flex gap-3">
                            {stats.cold.map((n, i) => (
                                <div key={i} className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm shadow-lg opacity-80 ${
                                    n === 0 ? 'bg-emerald-900/50 border border-emerald-500/50' : RED_NUMBERS.has(n) ? 'bg-red-900/50 border border-red-500/50' : 'bg-gray-900/50 border border-gray-600/50'
                                }`}>
                                    {n}
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="w-full h-px bg-white/10" />

                    {/* Percentages */}
                    <div className="space-y-4">
                        <StatBar 
                            label="Red / Black" 
                            leftLabel="Red" 
                            rightLabel="Black" 
                            leftVal={stats.redPct} 
                            rightVal={stats.blackPct} 
                            zeroVal={stats.zeroPct}
                            leftColor="bg-[#D92D28]" 
                            rightColor="bg-slate-700" 
                        />
                        <StatBar 
                            label="Even / Odd" 
                            leftLabel="Even" 
                            rightLabel="Odd" 
                            leftVal={stats.evenPct} 
                            rightVal={stats.oddPct} 
                            zeroVal={stats.zeroPct}
