                </div>
            </div>
            <style>{`
                @keyframes fade-in { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
                .animate-fade-in { animation: fade-in 0.2s ease-out; }
            `}</style>
        </div>,
        document.body
    );
};

const StatBar: React.FC<{
    label: string;
    leftLabel: string;
    rightLabel: string;
    leftVal: number;
    rightVal: number;
    zeroVal: number;
    leftColor: string;
    rightColor: string;
}> = ({ label, leftLabel, rightLabel, leftVal, rightVal, zeroVal, leftColor, rightColor }) => (
    <div>
        <div className="flex justify-between text-xs font-bold text-gray-300 mb-1.5">
