            </div>

            {/* Zero Bar */}
            <div className={`h-full bg-emerald-600 transition-all duration-500 flex items-center justify-center`} style={{ width: `${zeroVal}%` }}>
                {zeroVal > 8 && <span className="text-[8px] font-black text-white drop-shadow-md">0</span>}
            </div>

            {/* Right Bar */}
            <div className={`h-full ${rightColor} transition-all duration-500 flex items-center justify-end pr-1.5`} style={{ flex: 1 }}>
                {rightVal > 15 && <span className="text-[9px] font-black text-white drop-shadow-md uppercase truncate">{rightLabel}</span>}
            </div>
        </div>
    </div>
);

// ==========================================
// HISTORY PANEL
// ==========================================
export const HistoryPanel: React.FC<{history: number[]; stats: GameStats}> = ({ history, stats }) => {
    const last20 = history.slice(0, 20); // Sorted newest first
    const [showStats, setShowStats] = useState(false);

    return (
        <>
            <div className="w-full bg-slate-900/70 rounded-lg border border-white/10 p-2 sm:p-2.5 lg:p-4 shadow-inner lg:shadow-xl transition-all">
                <div className="flex flex-row gap-2 lg:gap-6">
                    {/* Left - Last 20 wrapping - SCROLLABLE */}
                    <div className="flex-1 min-w-0 overflow-hidden flex flex-col justify-center">
                        <div className="text-[10px] lg:text-xs text-gray-500 font-bold mb-1 lg:mb-3 uppercase tracking-widest pl-1">
                            Last 20 Draws
                        </div>

                        {/* Horizontal Scroll Container */}
                        <div className="flex items-center gap-1.5 lg:gap-2.5 overflow-x-auto scrollbar-hide w-full py-1.5 px-1" style={{scrollbarWidth: 'none', msOverflowStyle: 'none'}}>
                            <style>{`.scrollbar-hide::-webkit-scrollbar { display: none; }`}</style>
                            {last20.length === 0 ? (
                                <span className="text-gray-600 text-[10px] italic pl-1">Waiting for spin...</span>
                            ) : (
                                last20.map((n, i) => (
                                    <div 
                                        key={`${i}-${n}`} 
                                        className={`
                                            shrink-0 rounded-full flex items-center justify-center font-bold border shadow-sm transition-all
                                            w-5 h-5 text-[10px] lg:w-9 lg:h-9 lg:text-sm leading-none tracking-tighter
                                            ${i === 0 ? 'ring-2 ring-yellow-400 z-10 opacity-100 scale-105' : 'opacity-80'}
                                            ${n === 0 ? 'bg-emerald-600 border-emerald-400' : 
                                            RED_NUMBERS.has(n) ? 'bg-[#D92D28] border-red-400' : 'bg-zinc-800 border-zinc-500'}
                                        `}
                                    >
                                        {n}
                                    </div>
                                ))
                            )}
                            <div className="w-1 shrink-0" />
                        </div>
                    </div>

                    {/* Divider */}
                    <div className="w-px bg-white/10 self-stretch shrink-0" />

                    {/* Right - Hot/Cold stacked - CLICKABLE */}
                    <button 
                        onClick={() => setShowStats(true)}
                        className="relative flex flex-col gap-1 lg:gap-2 shrink-0 justify-center min-w-[fit-content] pr-1 pl-2 lg:pl-6 lg:pr-4 hover:bg-white/5 rounded-r-lg transition-colors group"
                        title="View Full Statistics"
                    >
                        {/* Hot */}
                        <div className="flex items-center gap-3 lg:gap-4">
                            <Flame size={12} className="text-orange-500 shrink-0 group-hover:scale-110 transition-transform lg:w-4 lg:h-4" />
                            <div className="flex gap-1.5 font-mono">
                                {stats.hot.map((n, i) => (
                                    <span key={`h${i}`} className={`text-xs lg:text-sm font-black ${n === 0 ? 'text-emerald-400' : RED_NUMBERS.has(n) ? 'text-red-400' : 'text-slate-200'}`}>{n}</span>
                                ))}
                            </div>
                        </div>
                        {/* Cold */}
                        <div className="flex items-center gap-3 lg:gap-4">
                            <Snowflake size={12} className="text-blue-500 shrink-0 group-hover:scale-110 transition-transform lg:w-4 lg:h-4" />
                            <div className="flex gap-1.5 font-mono">
                                {stats.cold.map((n, i) => (
                                    <span key={`c${i}`} className={`text-xs lg:text-sm font-black ${n === 0 ? 'text-emerald-400' : RED_NUMBERS.has(n) ? 'text-red-400' : 'text-slate-200'}`}>{n}</span>
                                ))}
                            </div>
                        </div>
                    </button>
                </div>
            </div>

            {/* Stats Modal */}
            {showStats && <StatsOverlay stats={stats} onClose={() => setShowStats(false)} />}
        </>
    );
};

// ==========================================
// CONTROL PANEL
// ==========================================
export const ControlPanel: React.FC<{
    chip: number;
    setChip: (v: number) => void;
    undo: () => void;
    clear: () => void;
    phase: GamePhase;
    hasBets: boolean;
    timeLeft: number;
    maxTime: number;
}> = ({ chip, setChip, undo, clear, phase, hasBets, timeLeft, maxTime }) => {

    const progress = (timeLeft / maxTime) * 100;

    return (
        <div className="w-full max-w-3xl mx-auto flex flex-col gap-3 relative z-20">
            {/* Status Window - Centered above, floating, pill-shaped */}
            <div className="self-center flex items-center gap-4 bg-slate-900/90 border border-white/10 px-8 py-2.5 rounded-full shadow-2xl backdrop-blur-md min-w-[240px] justify-center transition-all">
                 <div className={`text-sm sm:text-base font-black uppercase tracking-widest ${phase === 'betting' ? 'text-yellow-400' : 'text-slate-200'}`}>
                    {phase === 'betting' ? 'Place Your Bets' : phase === 'locked' ? 'No More Bets' : phase === 'spinning' ? 'Spinning...' : 'Winning Number'}
                 </div>
                 {phase === 'betting' && (
                     <div className="flex items-center gap-1.5 text-white font-mono font-bold bg-white/10 px-2 py-0.5 rounded">
                        <Clock size={14} className="text-yellow-400"/>
                        <span>{timeLeft}s</span>
                     </div>
                 )}
            </div>

            {/* Main Control Strip */}
            <div className="bg-[#1a1a2e] rounded-xl border border-white/10 shadow-2xl overflow-hidden flex flex-col">

                {/* Time Bar - Strictly Yellow */}
                <div className="h-1.5 w-full bg-slate-800">
                     <div 
                        className="h-full bg-yellow-400 transition-all duration-1000 ease-linear"
                        style={{ width: `${phase === 'betting' ? progress : 0}%` }}
                    />
                </div>

                {/* Buttons and Chips Row - Single Zone */}
                {/* Fixed height to prevent overflow issues with chips */}
                <div className="flex items-center justify-between p-3 sm:p-4 gap-2 sm:gap-4 h-20 sm:h-24">

                    {/* Clear (Left) - White */}
                    <button 
                        onClick={clear}
                        disabled={!hasBets || phase !== 'betting'}
                        className="w-12 h-12 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl bg-slate-800/50 hover:bg-white/10 border border-white/5 hover:border-white/20 text-white transition-all active:scale-95 disabled:opacity-30 disabled:pointer-events-none"
                        title="Clear Bets"
                    >
                        <Trash2 size={24} />
                    </button>

                    {/* Chips (Center) */}
                    <div className="flex-1 flex justify-center items-center gap-2 sm:gap-4 lg:gap-6 overflow-x-auto scrollbar-hide py-2 h-full">
                        {CHIP_VALUES.map(v => (
                            <button
                                key={v}
                                onClick={() => setChip(v)}
                                className={`
                                    relative transition-all duration-200 shrink-0
                                    ${chip === v ? '-translate-y-1.5 scale-110' : 'hover:-translate-y-1 hover:scale-105 opacity-80 hover:opacity-100'}
                                `}
                            >
                                <CasinoChip 
                                    value={v} 
                                    size="selector"
                                    className={chip === v ? "ring-2 ring-yellow-400 shadow-[0_0_15px_rgba(250,204,21,0.5)]" : ""} 
                                />
                            </button>
                        ))}
                    </div>

                    {/* Undo (Right) - White */}
                    <button 
                        onClick={undo}
                        disabled={!hasBets || phase !== 'betting'}
                        className="w-12 h-12 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl bg-slate-800/50 hover:bg-white/10 border border-white/5 hover:border-white/20 text-white transition-all active:scale-95 disabled:opacity-30 disabled:pointer-events-none"
                        title="Undo Last Bet"
                    >
                        <Undo2 size={24} />
                    </button>
                </div>
            </div>
        </div>
    );
};

