    else if (latestNet < 0) gainColor = 'text-red-400';

    return (
        <div className="relative shrink-0 z-40">
            <div className="flex items-center justify-end gap-3 sm:gap-6 px-4 py-2 bg-slate-900/60 border-b border-white/5 shadow-sm">
