// ==========================================
// LIVE FEED
// ==========================================
export const LiveFeed: React.FC<{feed: PlayerBet[]}> = ({ feed }) => {
    // Aggregate duplicate bets on the same number
    const aggregatedFeed = useMemo(() => {
        const map = new Map<string, { number: string; amount: number; count: number; recentUser: string }>();

        // Process feed in reverse to handle duplicates while preserving order of "newest appearance"
        // Actually, simple iteration is fine; we update existing or add new.
        // To keep the visual list sorted by "Most Recently Active", we can just use Map's insertion order if we delete and re-add,
        // but since we want to stabilize the feed, we just iterate the raw feed (which is newest first)
        // and build a list of unique numbers encountered.

        feed.forEach(bet => {
            if (map.has(bet.number)) {
                const existing = map.get(bet.number)!;
                existing.amount += bet.amount;
                existing.count += 1;
                // Keep the most recent user (first encountered in 'feed' array)
            } else {
                map.set(bet.number, {
                    number: bet.number,
                    amount: bet.amount,
                    count: 1,
                    recentUser: bet.username
                });
            }
        });

        return Array.from(map.values());
    }, [feed]);

    // Duplicate for marquee loop effect
    const displayItems = useMemo(() => [...aggregatedFeed, ...aggregatedFeed], [aggregatedFeed]);

    return (
        <div className="w-full bg-slate-900/80 overflow-hidden h-7 sm:h-8 flex items-center relative shrink-0 border-b border-white/5">
            <div className="absolute left-0 h-full w-8 bg-gradient-to-r from-slate-900 to-transparent z-10" />
            <div className="absolute right-0 h-full w-8 bg-gradient-to-l from-slate-900 to-transparent z-10" />
            <div className="whitespace-nowrap animate-marquee flex gap-6 px-4">
                {displayItems.map((item, i) => (
                    <div key={`${item.number}-${i}`} className="flex items-center gap-2 text-[10px] sm:text-xs text-gray-400 bg-white/5 px-2 py-0.5 rounded-full border border-white/5">
                        <span className={`px-1.5 py-0.5 rounded text-white text-[9px] font-bold min-w-[1.5rem] text-center shadow-sm ${
                            item.number === '0' ? 'bg-emerald-600' : RED_NUMBERS.has(+item.number) ? 'bg-[#D92D28]' : 'bg-black'
                        }`}>{item.number}</span>

                        <div className="flex items-center gap-1.5">
                            {item.count > 1 ? (
                                <>
                                    <span className="text-white font-semibold flex items-center gap-1">
                                        <Users size={10} className="text-gray-400" />
                                        {item.count} Bets
                                    </span>
                                    <span className="w-0.5 h-0.5 rounded-full bg-gray-500"/>
                                </>
                            ) : (
                                <>
                                    <span className="text-gray-300 font-medium truncate max-w-[80px]">{item.recentUser}</span>
                                    <span className="w-0.5 h-0.5 rounded-full bg-gray-500"/>
                                </>
                            )}
                            <span className="text-yellow-400 font-mono font-bold">${item.amount}</span>
                        </div>
                    </div>
                ))}
            </div>
            <style>{`
                @keyframes marquee { 0% { transform: translateX(-50%); } 100% { transform: translateX(0); } }
                .animate-marquee { animation: marquee 40s linear infinite; }
            `}</style>
        </div>
    );
};

