export const ControlPanel: React.FC<{
    chip: number;
    setChip: (v: number) => void;
    undo: () => void;
    clear: () => void;
    phase: GamePhase;
    hasBets: boolean;
    timeLeft: number;
    maxTime: number;
}> = ({ chip, setChip, undo, clear, phase, hasBets, timeLeft, maxTime }) => {

    const progress = (timeLeft / maxTime) * 100;

    return (
        <div className="w-full max-w-3xl mx-auto flex flex-col gap-3 relative z-20">
            {/* Status Window - Centered above, floating, pill-shaped */}
            <div className="self-center flex items-center gap-4 bg-slate-900/90 border border-white/10 px-8 py-2.5 rounded-full shadow-2xl backdrop-blur-md min-w-[240px] justify-center transition-all">
                 <div className={`text-sm sm:text-base font-black uppercase tracking-widest ${phase === 'betting' ? 'text-yellow-400' : 'text-slate-200'}`}>
                    {phase === 'betting' ? 'Place Your Bets' : phase === 'locked' ? 'No More Bets' : phase === 'spinning' ? 'Spinning...' : 'Winning Number'}
                 </div>
                 {phase === 'betting' && (
                     <div className="flex items-center gap-1.5 text-white font-mono font-bold bg-white/10 px-2 py-0.5 rounded">
                        <Clock size={14} className="text-yellow-400"/>
                        <span>{timeLeft}s</span>
                     </div>
                 )}
            </div>

            {/* Main Control Strip */}
            <div className="bg-[#1a1a2e] rounded-xl border border-white/10 shadow-2xl overflow-hidden flex flex-col">

                {/* Time Bar - Strictly Yellow */}
                <div className="h-1.5 w-full bg-slate-800">
                     <div 
                        className="h-full bg-yellow-400 transition-all duration-1000 ease-linear"
                        style={{ width: `${phase === 'betting' ? progress : 0}%` }}
                    />
                </div>

                {/* Buttons and Chips Row - Single Zone */}
                {/* Fixed height to prevent overflow issues with chips */}
                <div className="flex items-center justify-between p-3 sm:p-4 gap-2 sm:gap-4 h-20 sm:h-24">

                    {/* Clear (Left) - White */}
                    <button 
                        onClick={clear}
                        disabled={!hasBets || phase !== 'betting'}
                        className="w-12 h-12 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl bg-slate-800/50 hover:bg-white/10 border border-white/5 hover:border-white/20 text-white transition-all active:scale-95 disabled:opacity-30 disabled:pointer-events-none"
                        title="Clear Bets (Esc)"
                    >
                        <Trash2 size={24} />
                    </button>

                    {/* Chips (Center) */}
                    <div className="flex-1 flex justify-center items-center gap-2 sm:gap-4 lg:gap-6 overflow-x-auto scrollbar-hide py-2 h-full">
                        {CHIP_VALUES.map(v => (
                            <button
                                key={v}
                                onClick={() => setChip(v)}
                                className={`
                                    relative transition-all duration-200 shrink-0
                                    ${chip === v ? '-translate-y-1.5 scale-110' : 'hover:-translate-y-1 hover:scale-105 opacity-80 hover:opacity-100'}
                                `}
                            >
                                <CasinoChip 
                                    value={v} 
                                    size="selector"
                                    className={chip === v ? "ring-2 ring-yellow-400 shadow-[0_0_15px_rgba(250,204,21,0.5)]" : ""} 
                                />
                            </button>
                        ))}
                    </div>

                    {/* Undo (Right) - White */}
                    <button 
                        onClick={undo}
                        disabled={!hasBets || phase !== 'betting'}
                        className="w-12 h-12 sm:w-16 sm:h-16 flex items-center justify-center rounded-xl bg-slate-800/50 hover:bg-white/10 border border-white/5 hover:border-white/20 text-white transition-all active:scale-95 disabled:opacity-30 disabled:pointer-events-none"
                        title="Undo Last Bet (Del/Bksp)"
                    >
                        <Undo2 size={24} />
                    </button>
                </div>
            </div>
        </div>
    );
};

export type GamePhase = 'betting' | 'locked' | 'spinning' | 'result';

export interface PlayerBet {
  id: string;
  username: string;
  number: string;
  amount: number;
}

export interface BetAction {
  id: string;
  amount: number;
}

export interface ChipProps {
  value: number;
  className?: string;
  size?: "xs" | "sm" | "md" | "lg" | "board" | "selector";
}

export interface GameRecord {
  id: number;
  result: number;
  betAmount: number;
  winAmount: number;
  timestamp: Date;
}

export interface GameStats {
    hot: number[];
    cold: number[];
    redPct: number;
    blackPct: number;
    evenPct: number;
    oddPct: number;
    lowPct: number;
    highPct: number;
    zeroPct: number;
}

// Backend Data Structures (Motoko/Candid Compatibility)
export type BackendBetType = 
    | { Straight: number }
    | { Split: number[] }
    | { Street: number[] }
    | { Corner: number[] }
    | { Line: number[] }
    | { Trio: number[] }
    | { Basket: number[] }
    | { Column1: null }
    | { Column2: null }
    | { Column3: null }
    | { Dozen1: null }
    | { Dozen2: null }
    | { Dozen3: null }
    | { Red: null }
    | { Black: null }
    | { Odd: null }
    | { Even: null }
    | { Low: null }
    | { High: null };

export interface BackendBetEntry {
    betType: BackendBetType;
    amount: number;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { NavBar, LiveFeed, BalanceBar, HistoryPanel, ControlPanel, StatsOverlay } from './components/UI';
import BettingBoard from './components/BettingBoard';
import RouletteWheel3D from './components/RouletteWheel3D';
import { GamePhase, PlayerBet, BetAction, GameRecord, GameStats } from './types';
import { WHEEL_NUMBERS, CHIP_VALUES, BOT_NAMES } from './constants';
import { calculateWinnings, prepareBetsForBackend } from './utils';
import { soundManager } from './services/SoundManager';
import { mockBackend } from './services/MockBackend';

const App = () => {
    // Game State
    const [balance, setBalance] = useState(1000);
    const [bets, setBets] = useState<Record<string, number>>({});
    const [betStack, setBetStack] = useState<BetAction[]>([]);
    const [phase, setPhase] = useState<GamePhase>('betting');
    const [lastNum, setLastNum] = useState<number | null>(null);
    const [rotation, setRotation] = useState(0);

    // Backend Data
    const [history, setHistory] = useState<number[]>([]);
    const [stats, setStats] = useState<GameStats>({ hot: [], cold: [], redPct: 0, blackPct: 0, evenPct: 0, oddPct: 0, lowPct: 0, highPct: 0, zeroPct: 0 });
    const nextRoundData = useRef<{ history: number[], stats: GameStats } | null>(null);

    // Auto Spin State
    const BETTING_TIME = 25;
    const [timeLeft, setTimeLeft] = useState(BETTING_TIME);

    // UI State
    const [chip, setChip] = useState(5);
    const [feed, setFeed] = useState<PlayerBet[]>([]);
    const [muted, setMuted] = useState(false);
    const [showRec, setShowRec] = useState(false);
    const [showStats, setShowStats] = useState(false); // Stats Overlay State
    const [records, setRecords] = useState<GameRecord[]>([]);

    const betTotal = betStack.reduce((s, b) => s + b.amount, 0);
    const SPIN_DURATION = 25000;

    // Load Initial Data
    useEffect(() => {
        mockBackend.getInitialData().then(data => {
            setHistory(data.history);
            setStats(data.stats);
        });
    }, []);

    // Simulated Multiplayer Feed
    useEffect(() => {
        const i = setInterval(() => {
            if (Math.random() > 0.4) {
                setFeed(f => [{
                    id: `bet-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
                    username: BOT_NAMES[Math.floor(Math.random() * BOT_NAMES.length)],
                    number: String(Math.floor(Math.random() * 37)),
                    amount: CHIP_VALUES[Math.floor(Math.random() * CHIP_VALUES.length)]
                }, ...f].slice(0, 20));
            }
        }, 1500); // Slightly faster to show activity
        return () => clearInterval(i);
    }, []);

    // Sync Mute State
    useEffect(() => { soundManager.setMuted(muted); }, [muted]);

    const placeBet = (id: string) => {
        if (phase !== 'betting' || balance < chip) return;
        soundManager.playChipPlace();
        setBalance(b => b - chip);
        setBets(b => ({ ...b, [id]: (b[id] || 0) + chip }));
        setBetStack(s => [...s, { id, amount: chip }]);
    };

    const undo = useCallback(() => {
        if (phase !== 'betting' || !betStack.length) return;
        soundManager.playUndo();
        const last = betStack[betStack.length - 1];
        setBalance(b => b + last.amount);
        setBets(b => {
            const n = { ...b };
            n[last.id] -= last.amount;
            if (n[last.id] <= 0) delete n[last.id];
            return n;
        });
        setBetStack(s => s.slice(0, -1));
    }, [phase, betStack]);

    const clear = useCallback(() => {
        if (phase !== 'betting' || betStack.length === 0) return;
        soundManager.playClear();
        setBalance(b => b + betStack.reduce((s, x) => s + x.amount, 0));
        setBets({});
        setBetStack([]);
    }, [phase, betStack]);

    // Keyboard Shortcuts
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            // Ignore if user is interacting with form elements
            if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

            if (phase === 'betting') {
                if (e.key === 'Escape') {
                    undo();
                } else if (e.key === 'Delete') {
                    clear();
                }
            }
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [phase, clear, undo]);

    // Trigger Spin Animation
    const spin = useCallback((winningNumber: number) => {
        setPhase('spinning');
        soundManager.playSpinSound(SPIN_DURATION);

        const resultIndex = WHEEL_NUMBERS.indexOf(winningNumber);
        const anglePerItem = 360 / 37;
        const targetAngle = resultIndex * anglePerItem;

        setRotation(prevRotation => {
            const currentMod = prevRotation % 360;
            const targetMod = (360 - targetAngle) % 360; 
            let diff = targetMod - currentMod;
            if (diff < 0) diff += 360; 
            return prevRotation + (12 * 360) + diff;
        });

        setTimeout(() => {
            setLastNum(winningNumber);
            setPhase('result');
        }, SPIN_DURATION);
    }, []); 

    // Handle Game Flow
    const handleGameSequence = useCallback(async () => {
        if (phase !== 'betting') return;

        setPhase('locked');

        const backendPayload = prepareBetsForBackend(bets);

        try {
            // Call Backend
            const { result, history: newHistory, stats: newStats } = await mockBackend.placeBets(backendPayload);

            // Store new data to apply after spin
            nextRoundData.current = { history: newHistory, stats: newStats };

            // Start Animation
            spin(result);

        } catch (error) {
            console.error("Backend Error:", error);
            setPhase('betting'); 
        }

    }, [phase, bets, spin]);

    // Post-Spin Result Logic
    useEffect(() => {
        if (phase === 'result' && lastNum !== null) {
            // Calculate Winnings
            const winAmount = calculateWinnings(lastNum, bets);

            if (winAmount > 0) {
                setBalance(b => b + winAmount);
                soundManager.playWin();
            } else {
                soundManager.playLose();
            }

            // Update History and Stats from Backend response
            if (nextRoundData.current) {
                setHistory(nextRoundData.current.history);
                setStats(nextRoundData.current.stats);
                nextRoundData.current = null;
            }

            // Record Game for User Log
            setRecords(prev => [{
                id: Date.now(),
                result: lastNum,
                betAmount: betTotal,
                winAmount: winAmount,
                timestamp: new Date()
            }, ...prev]);

            // Auto Reset
            const timer = setTimeout(() => {
                setPhase('betting');
                setLastNum(null);
                setBets({});
                setBetStack([]);
                setTimeLeft(BETTING_TIME);
            }, 3500);
            return () => clearTimeout(timer);
        }
    }, [phase, lastNum]);

    // Timer Tick
    useEffect(() => {
        if (phase === 'betting' && timeLeft > 0) {
            const timer = setTimeout(() => setTimeLeft(t => Math.max(0, t - 1)), 1000);
            return () => clearTimeout(timer);
        }
    }, [phase, timeLeft]);

    // Trigger Game Sequence on Time Up
    useEffect(() => {
        if (phase === 'betting' && timeLeft === 0) {
            handleGameSequence();
        }
    }, [phase, timeLeft, handleGameSequence]);

    return (
        <div className="relative w-full h-screen bg-[#0f172a] text-white font-sans select-none overflow-hidden">
            <div className="absolute inset-0 flex flex-col">
                <NavBar 
                    onExit={() => window.location.reload()} 
                    isMuted={muted} 
                    setIsMuted={setMuted}
                />

                <LiveFeed feed={feed} />

                <BalanceBar 
                    balance={balance} 
                    betTotal={betTotal} 
                    records={records}
                    showRec={showRec}
                    setShowRec={setShowRec}
                />

                {/* Content Container */}
                <main className="flex-1 w-full max-w-[1800px] mx-auto p-2 sm:p-4 lg:p-8 flex flex-col lg:flex-row items-stretch justify-center gap-2 lg:gap-16 overflow-y-auto">

                    {/* Left Section (Wheel & Stats) */}
                    <div className="flex-shrink-0 flex flex-col items-center lg:items-center justify-between lg:justify-end z-0 relative lg:w-[500px] lg:gap-8">
                        <div className="flex-shrink-0 lg:flex-none flex items-center justify-center w-full lg:mb-28 min-h-[250px] sm:min-h-[300px]">
                            <div className="transform scale-[0.65] sm:scale-75 md:scale-90 lg:scale-110 xl:scale-125 transition-transform duration-500 origin-center -my-6 sm:my-0">
                                <RouletteWheel3D rotation={rotation} lastNumber={lastNum} spinDuration={SPIN_DURATION} />
                            </div>
                        </div>

                        <div className="hidden lg:block w-full">
                            <HistoryPanel history={history} stats={stats} onShowStats={() => setShowStats(true)} />
                        </div>
                    </div>

                    {/* Right Section (Board & Controls) */}
                    <div className="shrink-0 lg:flex-1 w-full max-w-[700px] flex flex-col gap-1.5 sm:gap-4 lg:gap-8 lg:h-auto justify-end lg:justify-end z-10 pb-1 lg:pb-0">
                        <div className="lg:hidden w-full">
                            <HistoryPanel history={history} stats={stats} onShowStats={() => setShowStats(true)} />
                        </div>

                        <div className="w-full flex items-center justify-center min-h-0">
                            <BettingBoard bets={bets} onBet={placeBet} phase={phase} />
                        </div>

                        <ControlPanel 
                            chip={chip} 
                            setChip={setChip} 
                            undo={undo} 
                            clear={clear} 
                            phase={phase}
                            hasBets={betTotal > 0}
                            timeLeft={timeLeft}
                            maxTime={BETTING_TIME}
                        />
                    </div>
                </main>

                {/* Render StatsOverlay at root level to ensure it sits on top of everything */}
                {showStats && <StatsOverlay stats={stats} onClose={() => setShowStats(false)} />}
            </div>
        </div>
    );
};

export default App;

