                    <span className="text-[10px] font-bold text-gray-500 uppercase tracking-wider group-hover:text-gray-300 transition-colors">Last</span>
                    <div className="flex items-center gap-1">
                        <span className={`font-mono font-bold text-base sm:text-xl filter drop-shadow-sm ${gainColor}`}>
                            {latestNet > 0 ? '+' : ''}{latestNet === 0 ? '$0' : `$${latestNet}`}
                        </span>
                        {showRec ? <ChevronUp size={14} className="text-gray-400" /> : <ChevronDown size={14} className="text-gray-400" />}
